{
  "name": "Rotary Table ISO 230-2 Metrology Suite",
  "description": "Professional angular position accuracy testing software for DD rotary tables using 24-sided prism and autocollimator, compliant with ISO 230-2 standards."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface PrismFaceData {
  face: number;
  targetAngle: number;
  error: number; // 棱体自身偏差 (arcsec)
}

export interface Reading {
  forward: number[]; // 多次往返测量值 (arcsec)
  reverse: number[];
}

export interface MeasurementPoint {
  face: number;
  targetAngle: number;
  forwardReadings: number[];
  reverseReadings: number[];
}

export interface ISOResult {
  A: number; // 双向定位精度
  A_up: number; // 正向定位精度
  A_down: number; // 反向定位精度
  R: number; // 双向重复定位精度
  R_up: number; // 正向重复定位精度
  R_down: number; // 反向重复定位精度
  B: number; // 反向差值 (回程误差)
  E: number; // 定位偏差
  E_up: number;
  E_down: number;
  points: CalculatedPoint[];
}

export interface CalculatedPoint {
  angle: number;
  meanForward: number;
  meanReverse: number;
  stdForward: number;
  stdReverse: number;
  deviationForward: number;
  deviationReverse: number;
  reversalError: number;
}

import { MeasurementPoint, PrismFaceData, ISOResult, CalculatedPoint } from '../types';

export const calculateISO230 = (
  measurements: MeasurementPoint[],
  prismData: PrismFaceData[]
): ISOResult => {
  const points: CalculatedPoint[] = measurements.map((m, i) => {
    const prismError = prismData[i].error;

    // 修正后的偏差 = 读数 - 棱体偏差
    const correctedF = m.forwardReadings.map(v => v - prismError);
    const correctedR = m.reverseReadings.map(v => v - prismError);

    const meanF = correctedF.reduce((a, b) => a + b, 0) / correctedF.length;
    const meanR = correctedR.reduce((a, b) => a + b, 0) / correctedR.length;

    const stdF = Math.sqrt(correctedF.reduce((sq, n) => sq + Math.pow(n - meanF, 2), 0) / (correctedF.length - 1)) || 0;
    const stdR = Math.sqrt(correctedR.reduce((sq, n) => sq + Math.pow(n - meanR, 2), 0) / (correctedR.length - 1)) || 0;

    return {
      angle: m.targetAngle,
      meanForward: meanF,
      meanReverse: meanR,
      stdForward: stdF,
      stdReverse: stdR,
      deviationForward: meanF, // 简化处理，假设基准为0
      deviationReverse: meanR,
      reversalError: Math.abs(meanF - meanR)
    };
  });

  // ISO 230-2 指标计算
  const A_up_vals = points.map(p => p.meanForward + 2 * p.stdForward);
  const A_down_vals = points.map(p => p.meanReverse - 2 * p.stdReverse);

  const A_up = Math.max(...A_up_vals) - Math.min(...points.map(p => p.meanForward - 2 * p.stdForward));
  const A_down = Math.max(...points.map(p => p.meanReverse + 2 * p.stdReverse)) - Math.min(...A_down_vals);

  const R_up = Math.max(...points.map(p => 4 * p.stdForward));
  const R_down = Math.max(...points.map(p => 4 * p.stdReverse));

  const B = Math.max(...points.map(p => Math.abs(p.meanForward - p.meanReverse)));
  const E = Math.max(...points.map(p => p.meanForward), ...points.map(p => p.meanReverse)) - 
            Math.min(...points.map(p => p.meanForward), ...points.map(p => p.meanReverse));

  return {
    A: Math.max(...A_up_vals, ...points.map(p => p.meanReverse + 2 * p.stdReverse)) - 
       Math.min(...points.map(p => p.meanForward - 2 * p.stdForward), ...A_down_vals),
    A_up,
    A_down,
    R: Math.max(...points.map(p => 4 * p.stdForward + Math.abs(p.meanForward - p.meanReverse) + 4 * p.stdReverse)) / 2, // 简化版
    R_up,
    R_down,
    B,
    E,
    E_up: Math.max(...points.map(p => p.meanForward)) - Math.min(...points.map(p => p.meanForward)),
    E_down: Math.max(...points.map(p => p.meanReverse)) - Math.min(...points.map(p => p.meanReverse)),
    points
  };
};

import { GoogleGenAI } from "@google/genai";
import { ISOResult } from "../types";

export const analyzeTestResults = async (results: ISOResult): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    作为计量院资深工程师，请分析以下直驱转台的测试数据（ISO 230-2标准）：

    测试结果：
    - 双向定位精度 (A): ${results.A.toFixed(2)} "
    - 重复定位精度 (R): ${results.R.toFixed(2)} "
    - 反向差值 (B): ${results.B.toFixed(2)} "
    - 定位偏差 (E): ${results.E.toFixed(2)} "

    数据详情：
    ${results.points.map(p => `角度 ${p.angle}°: 正向偏差 ${p.meanForward.toFixed(2)}", 反向偏差 ${p.meanReverse.toFixed(2)}"`).join('\n')}

    请提供：
    1. 精度评价（是否合格，通常直驱转台精度在1-5秒以内）。
    2. 误差原因分析（如：周期性误差可能源于编码器安装偏心、反向误差大可能源于控制算法或轴承预紧）。
    3. 维护建议。
    4. 简短总结。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "未能生成分析报告。";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "AI 分析服务暂不可用。";
  }
};

import React from 'react';
import { PrismFaceData } from '../types';

interface Props {
