        <h3 className="font-semibold text-slate-700">24面棱体修正值 (arcsec)</h3>
        <span className="text-xs text-slate-500">ISO 230-2 溯源</span>
      </div>
      <div className="max-h-96 overflow-y-auto">
        <table className="w-full text-sm text-left">
