export default PrismTable;

import React from 'react';
import { MeasurementPoint } from '../types';

interface Props {
  measurements: MeasurementPoint[];
  onChange: (faceIdx: number, type: 'forward' | 'reverse', runIdx: number, value: number) => void;
  numRuns: number;
}

const MeasurementTable: React.FC<Props> = ({ measurements, onChange, numRuns }) => {
  return (
    <div className="bg-white rounded-lg shadow-sm border overflow-hidden">
      <div className="bg-blue-50 px-4 py-2 border-b flex justify-between items-center">
        <h3 className="font-semibold text-blue-900">准直仪实测数据 (")</h3>
        <div className="flex gap-2">
           <span className="px-2 py-0.5 bg-blue-100 text-blue-700 text-xs rounded-full">Forward Runs: {numRuns}</span>
        </div>
