              <th className="px-4 py-1 text-center border-b border-r" colSpan={numRuns}>正向 (Forward)</th>
              <th className="px-4 py-1 text-center border-b" colSpan={numRuns}>反向 (Reverse)</th>
            </tr>
            <tr className="border-b bg-slate-50">
              {[...Array(numRuns)].map((_, i) => (
                <th key={`fh-${i}`} className="px-2 py-1 text-center border-r">R{i+1}</th>
