              <tr key={m.face} className="hover:bg-blue-50 transition-colors">
                <td className="px-4 py-2 font-mono font-medium border-r bg-slate-50">{m.targetAngle}°</td>
                {m.forwardReadings.map((val, runIdx) => (
                  <td key={`f-${faceIdx}-${runIdx}`} className="px-1 py-1 border-r">
                    <input
