                      step="0.01"
                      value={val}
                      onChange={(e) => onChange(faceIdx, 'reverse', runIdx, parseFloat(e.target.value) || 0)}
                      className="w-full px-1 py-1 border border-transparent focus:border-blue-300 focus:bg-white bg-transparent outline-none text-center font-mono"
                    />
