export default MeasurementTable;

import React, { useState, useMemo, useEffect } from 'react';
import { PrismFaceData, MeasurementPoint, ISOResult } from './types';
import PrismTable from './components/PrismTable';
import MeasurementTable from './components/MeasurementTable';
import ResultDashboard from './components/ResultDashboard';
import { calculateISO230 } from './services/isoCalculator';
import { analyzeTestResults } from './services/geminiService';
import { Settings, ClipboardCheck, BarChart3, HelpCircle, FileText, ChevronRight, Activity, Cpu } from 'lucide-react';

const NUM_FACES = 24;
const INITIAL_PRISM_DATA: PrismFaceData[] = Array.from({ length: NUM_FACES }, (_, i) => ({
  face: i + 1,
  targetAngle: i * 15,
  error: 0
}));

const INITIAL_MEASUREMENTS: (numRuns: number) => MeasurementPoint[] = (numRuns) => 
  Array.from({ length: NUM_FACES }, (_, i) => ({
    face: i + 1,
    targetAngle: i * 15,
    forwardReadings: Array(numRuns).fill(0),
    reverseReadings: Array(numRuns).fill(0)
  }));

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'config' | 'measure' | 'results'>('config');
  const [numRuns, setNumRuns] = useState(3);
  const [prismData, setPrismData] = useState<PrismFaceData[]>(INITIAL_PRISM_DATA);
  const [measurements, setMeasurements] = useState<MeasurementPoint[]>(INITIAL_MEASUREMENTS(3));
  const [aiReport, setAiReport] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // 当运行次数改变时重置数据
  useEffect(() => {
    setMeasurements(INITIAL_MEASUREMENTS(numRuns));
  }, [numRuns]);

  const results = useMemo(() => calculateISO230(measurements, prismData), [measurements, prismData]);

  const handlePrismChange = (index: number, error: number) => {
    const newData = [...prismData];
    newData[index].error = error;
    setPrismData(newData);
  };

  const handleMeasurementChange = (faceIdx: number, type: 'forward' | 'reverse', runIdx: number, value: number) => {
    const newMeasurements = [...measurements];
    if (type === 'forward') {
      newMeasurements[faceIdx].forwardReadings[runIdx] = value;
    } else {
      newMeasurements[faceIdx].reverseReadings[runIdx] = value;
    }
    setMeasurements(newMeasurements);
  };

  const handleGenerateReport = async () => {
    setIsAnalyzing(true);
    setAiReport(null);
    try {
      const report = await analyzeTestResults(results);
      setAiReport(report);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const exportCSV = () => {
    const headers = ['Angle', 'PrismErr', ...Array(numRuns).fill(0).map((_,i)=>`F${i+1}`), ...Array(numRuns).fill(0).map((_,i)=>`R${i+1}`)];
    const rows = measurements.map((m, i) => [
      m.targetAngle,
      prismData[i].error,
      ...m.forwardReadings,
      ...m.reverseReadings
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `Rotary_Test_Report_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-slate-900 text-white px-6 py-4 flex items-center justify-between shadow-lg z-50">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-600 rounded-lg">
            <Activity className="w-6 h-6" />
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight">直驱转台精度测试系统</h1>
            <p className="text-xs text-slate-400">符合 ISO 230-2 标准 • 计量院专业版</p>
          </div>
        </div>
        <div className="flex gap-4">
          <button onClick={exportCSV} className="px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-md text-sm transition-colors flex items-center gap-2">
             <FileText className="w-4 h-4" /> 导出 CSV
          </button>
          <div className="flex items-center gap-2 bg-slate-800 px-3 py-1.5 rounded-md border border-slate-700">
            <Settings className="w-4 h-4 text-slate-400" />
            <label className="text-xs text-slate-300">测量循环次数:</label>
            <select 
              value={numRuns} 
              onChange={(e) => setNumRuns(parseInt(e.target.value))}
              className="bg-transparent text-xs outline-none cursor-pointer"
            >
              {[2, 3, 5, 7, 10].map(v => <option key={v} value={v} className="bg-slate-800">{v}</option>)}
            </select>
          </div>
        </div>
      </header>

      {/* Main Layout */}
      <div className="flex-1 flex overflow-hidden">
        {/* Sidebar Navigation */}
        <aside className="w-64 bg-white border-r flex flex-col shadow-sm z-40">
          <nav className="flex-1 p-4 space-y-2">
            <button
              onClick={() => setActiveTab('config')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all ${activeTab === 'config' ? 'bg-blue-50 text-blue-600' : 'text-slate-600 hover:bg-slate-50'}`}
            >
              <Settings className="w-5 h-5" />
              1. 棱体修正值配置
              {activeTab === 'config' && <ChevronRight className="ml-auto w-4 h-4" />}
            </button>
            <button
              onClick={() => setActiveTab('measure')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all ${activeTab === 'measure' ? 'bg-blue-50 text-blue-600' : 'text-slate-600 hover:bg-slate-50'}`}
            >
              <ClipboardCheck className="w-5 h-5" />
              2. 数据录入/采集
              {activeTab === 'measure' && <ChevronRight className="ml-auto w-4 h-4" />}
            </button>
            <button
              onClick={() => setActiveTab('results')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all ${activeTab === 'results' ? 'bg-blue-50 text-blue-600' : 'text-slate-600 hover:bg-slate-50'}`}
            >
              <BarChart3 className="w-5 h-5" />
              3. 分析报告与结果
              {activeTab === 'results' && <ChevronRight className="ml-auto w-4 h-4" />}
            </button>
          </nav>

          <div className="p-4 border-t bg-slate-50">
            <div className="p-3 bg-white rounded-lg border shadow-sm">
              <div className="flex items-center gap-2 mb-2 text-blue-600">
                <HelpCircle className="w-4 h-4" />
                <span className="text-xs font-bold uppercase">使用说明</span>
              </div>
              <p className="text-[11px] text-slate-500 leading-relaxed">
                1. 输入24面棱体检定证书上的偏差值。<br/>
                2. 记录每个停止位正反向实测读数。<br/>
                3. 系统自动完成棱体误差修正并计算 ISO 230-2 参数。
              </p>
            </div>
          </div>
        </aside>

        {/* Content Area */}
        <main className="flex-1 overflow-y-auto bg-slate-50 p-8">
          <div className="max-w-6xl mx-auto space-y-8">
            {activeTab === 'config' && (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300">
                <header>
                  <h2 className="text-2xl font-bold text-slate-800">棱体误差配置</h2>
                  <p className="text-slate-500">请输入24面棱体各面的修正值，用于消除检测链路中的系统误差。</p>
                </header>
                <PrismTable data={prismData} onChange={handlePrismChange} />
                <div className="flex justify-end">
                  <button 
                    onClick={() => setActiveTab('measure')}
                    className="px-6 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium shadow-md flex items-center gap-2 transition-all"
                  >
                    下一步：录入数据 <ChevronRight className="w-4 h-4" />
                  </button>
                </div>
              </div>
            )}

            {activeTab === 'measure' && (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300">
                <header>
                  <h2 className="text-2xl font-bold text-slate-800">数据采集</h2>
                  <p className="text-slate-500">请输入准直仪读取的各角度角位置偏差（单位：秒）。</p>
                </header>
                <MeasurementTable 
                  measurements={measurements} 
                  onChange={handleMeasurementChange} 
                  numRuns={numRuns}
                />
                <div className="flex justify-end gap-4">
                  <button 
                    onClick={() => setActiveTab('config')}
                    className="px-6 py-2.5 border border-slate-300 text-slate-600 rounded-lg font-medium hover:bg-slate-50"
                  >
                    上一步
                  </button>
                  <button 
                    onClick={() => setActiveTab('results')}
                    className="px-6 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium shadow-md flex items-center gap-2 transition-all"
                  >
                    查看分析结果 <BarChart3 className="w-4 h-4" />
                  </button>
                </div>
              </div>
            )}

            {activeTab === 'results' && (
              <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300 pb-20">
                <div className="flex justify-between items-end">
                  <header>
                    <h2 className="text-2xl font-bold text-slate-800">ISO 230-2 精度评估</h2>
                    <p className="text-slate-500">基于实测数据自动计算的转台几何精度指标。</p>
                  </header>
                  <button 
                    onClick={handleGenerateReport}
                    disabled={isAnalyzing}
                    className="px-6 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-medium shadow-md flex items-center gap-2 disabled:opacity-50 transition-all"
                  >
                    <Cpu className={`w-4 h-4 ${isAnalyzing ? 'animate-spin' : ''}`} />
                    {isAnalyzing ? 'AI 分析中...' : '生成 AI 技术分析'}
                  </button>
                </div>

                <ResultDashboard results={results} />

                {aiReport && (
                  <div className="bg-white p-8 rounded-xl shadow-sm border-l-4 border-indigo-500 space-y-4 animate-in fade-in zoom-in-95 duration-500">
                    <div className="flex items-center gap-3 text-indigo-600">
                      <Cpu className="w-6 h-6" />
                      <h3 className="text-lg font-bold">AI 智能专家报告</h3>
                    </div>
                    <div className="prose prose-slate max-w-none text-slate-700 leading-relaxed whitespace-pre-line">
                      {aiReport}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </main>
      </div>

      {/* Footer / Status Bar */}
      <footer className="bg-white border-t px-6 py-2 text-[10px] text-slate-400 flex justify-between uppercase tracking-widest font-mono">
        <div className="flex gap-4">
          <span>Standard: ISO 230-2:2014</span>
          <span>Sample Rate: 1Hz (Manual)</span>
          <span>Instrument: Autocollimator (0.01" Resolution)</span>
        </div>
        <div>
          Metrology Suite v2.4.0 • Building Digital Trust
        </div>
      </footer>
    </div>
  );
};

export default App;

import { MeasurementPoint, PrismFaceData, ISOResult, CalculatedPoint } from '../types';

export const calculateISO230 = (
  measurements: MeasurementPoint[],
  prismData: PrismFaceData[]
): ISOResult => {
  // 零点归一化：以第一个正向行程的第一个读数为基准 (Initial Offset)
  const firstForwardRun = measurements[0]?.forwardReadings[0] || 0;

  const points: CalculatedPoint[] = measurements.map((m, i) => {
    const prismError = prismData[i].error;

    // 修正后的读数 = (原始读数 - 初始零位偏移) - 棱体偏差
    // 注意：棱体偏差通常是加在理论值上的误差，所以计算偏差时需要减去它
    const correctedF = m.forwardReadings.map(v => (v - firstForwardRun) - prismError);
    const correctedR = m.reverseReadings.map(v => (v - firstForwardRun) - prismError);

    const meanF = correctedF.reduce((a, b) => a + b, 0) / correctedF.length;
    const meanR = correctedR.reduce((a, b) => a + b, 0) / correctedR.length;

    const stdF = Math.sqrt(correctedF.reduce((sq, n) => sq + Math.pow(n - meanF, 2), 0) / (correctedF.length - 1)) || 0;
    const stdR = Math.sqrt(correctedR.reduce((sq, n) => sq + Math.pow(n - meanR, 2), 0) / (correctedR.length - 1)) || 0;

    return {
      angle: m.targetAngle,
      meanForward: meanF,
      meanReverse: meanR,
      stdForward: stdF,
      stdReverse: stdR,
      deviationForward: meanF,
      deviationReverse: meanR,
      reversalError: Math.abs(meanF - meanR)
    };
  });

  // ISO 230-2 指标计算
  const A_up_vals = points.map(p => p.meanForward + 2 * p.stdForward);
  const A_down_vals = points.map(p => p.meanReverse - 2 * p.stdReverse);

  const minF = Math.min(...points.map(p => p.meanForward - 2 * p.stdForward));
  const maxF = Math.max(...A_up_vals);
  const A_up = maxF - minF;

  const minR = Math.min(...A_down_vals);
  const maxR = Math.max(...points.map(p => p.meanReverse + 2 * p.stdReverse));
  const A_down = maxR - minR;

  const R_up = Math.max(...points.map(p => 4 * p.stdForward));
  const R_down = Math.max(...points.map(p => 4 * p.stdReverse));

  const B = Math.max(...points.map(p => Math.abs(p.meanForward - p.meanReverse)));
  const E = Math.max(...points.map(p => p.meanForward), ...points.map(p => p.meanReverse)) - 
            Math.min(...points.map(p => p.meanForward), ...points.map(p => p.meanReverse));

  return {
    A: Math.max(maxF, maxR) - Math.min(minF, minR),
    A_up,
    A_down,
    R: Math.max(...points.map(p => 4 * p.stdForward + Math.abs(p.meanForward - p.meanReverse) + 4 * p.stdReverse)) / 2,
    R_up,
    R_down,
    B,
    E,
    E_up: Math.max(...points.map(p => p.meanForward)) - Math.min(...points.map(p => p.meanForward)),
    E_down: Math.max(...points.map(p => p.meanReverse)) - Math.min(...points.map(p => p.meanReverse)),
    points
  };
};

