import React, { useState, useMemo, useEffect } from 'react';
import { PrismFaceData, MeasurementPoint, ISOResult } from './types';
import PrismTable from './components/PrismTable';
import MeasurementTable from './components/MeasurementTable';
import ResultDashboard from './components/ResultDashboard';
import { calculateISO230 } from './services/isoCalculator';
import { analyzeTestResults } from './services/geminiService';
import { Settings, ClipboardCheck, BarChart3, HelpCircle, FileText, ChevronRight, Activity, Cpu, X, AlertCircle } from 'lucide-react';

const NUM_FACES = 24;
const INITIAL_PRISM_DATA: PrismFaceData[] = Array.from({ length: NUM_FACES }, (_, i) => ({
  face: i + 1,
  targetAngle: i * 15,
  error: 0
}));

const INITIAL_MEASUREMENTS: (numRuns: number) => MeasurementPoint[] = (numRuns) => 
  Array.from({ length: NUM_FACES }, (_, i) => ({
    face: i + 1,
    targetAngle: i * 15,
    forwardReadings: Array(numRuns).fill(0),
    reverseReadings: Array(numRuns).fill(0)
  }));

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'config' | 'measure' | 'results'>('config');
  const [numRuns, setNumRuns] = useState(3);
  const [prismData, setPrismData] = useState<PrismFaceData[]>(INITIAL_PRISM_DATA);
  const [measurements, setMeasurements] = useState<MeasurementPoint[]>(INITIAL_MEASUREMENTS(3));
  const [aiReport, setAiReport] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showBulkModal, setShowBulkModal] = useState(false);
  const [bulkInput, setBulkInput] = useState('');

  // Sync measurements grid when number of runs changes
  useEffect(() => {
    setMeasurements(prev => {
      return prev.map(m => ({
        ...m,
        forwardReadings: m.forwardReadings.length === numRuns ? m.forwardReadings : Array(numRuns).fill(0),
        reverseReadings: m.reverseReadings.length === numRuns ? m.reverseReadings : Array(numRuns).fill(0)
      }));
    });
  }, [numRuns]);

  const results = useMemo(() => calculateISO230(measurements, prismData), [measurements, prismData]);

  const handlePrismChange = (index: number, error: number) => {
    const newData = [...prismData];
    newData[index].error = error;
    setPrismData(newData);
  };

  const handleMeasurementChange = (faceIdx: number, type: 'forward' | 'reverse', runIdx: number, value: number) => {
    const newMeasurements = [...measurements];
    if (type === 'forward') {
      newMeasurements[faceIdx].forwardReadings[runIdx] = value;
    } else {
      newMeasurements[faceIdx].reverseReadings[runIdx] = value;
    }
    setMeasurements(newMeasurements);
  };

  const handleBulkImport = () => {
    // 处理逻辑：按行分割，每行可能包含多个数据列
    const rows = bulkInput.trim().split(/\r?\n/);
    const newMeasurements = [...measurements];

    // 如果数据是两列（一列正向一列反向）
    // 或者是一长列（前24个正向，后24个反向）
    // 这里采用更灵活的解析：提取所有数字，按序填入
    const allNumbers = bulkInput.trim().split(/[\t\s\n,]+/).map(v => parseFloat(v)).filter(v => !isNaN(v));

    if (allNumbers.length === 0) return;

    let index = 0;
    // 假设用户输入的顺序是：Run1(正24, 反24), Run2(正24, 反24)...
    for (let r = 0; r < numRuns; r++) {
      // 正向行程
      for (let f = 0; f < NUM_FACES; f++) {
        if (index < allNumbers.length) {
          newMeasurements[f].forwardReadings[r] = allNumbers[index++];
        }
      }
      // 反向行程
      for (let f = 0; f < NUM_FACES; f++) {
        if (index < allNumbers.length) {
          newMeasurements[f].reverseReadings[r] = allNumbers[index++];
        }
      }
    }

    setMeasurements(newMeasurements);
    setShowBulkModal(false);
    setBulkInput('');
  };

  const handleGenerateReport = async () => {
    setIsAnalyzing(true);
    setAiReport(null);
    try {
      const report = await analyzeTestResults(results);
      setAiReport(report);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const exportCSV = () => {
    const headers = ['Angle', 'PrismErr', ...Array(numRuns).fill(0).map((_,i)=>`F${i+1}`), ...Array(numRuns).fill(0).map((_,i)=>`R${i+1}`)];
    const rows = measurements.map((m, i) => [
      m.targetAngle,
      prismData[i].error,
      ...m.forwardReadings,
      ...m.reverseReadings
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `Rotary_Test_Report_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-slate-900 text-white px-6 py-4 flex items-center justify-between shadow-lg z-50">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-600 rounded-lg">
            <Activity className="w-6 h-6" />
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight">直驱转台精度测试系统</h1>
            <p className="text-xs text-slate-400">符合 ISO 230-2 标准 • 零位自动修正</p>
          </div>
        </div>
        <div className="flex gap-4">
          <button onClick={exportCSV} className="px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-md text-sm transition-colors flex items-center gap-2 border border-slate-700">
             <FileText className="w-4 h-4" /> 导出结果
          </button>
          <div className="flex items-center gap-2 bg-slate-800 px-3 py-1.5 rounded-md border border-slate-700">
            <Settings className="w-4 h-4 text-slate-400" />
            <label className="text-xs text-slate-300">循环次数 (Runs):</label>
            <select 
              value={numRuns} 
              onChange={(e) => setNumRuns(parseInt(e.target.value))}
              className="bg-transparent text-xs outline-none cursor-pointer font-bold text-blue-400"
            >
              {[1, 2, 3, 5, 10].map(v => <option key={v} value={v} className="bg-slate-800">{v}</option>)}
            </select>
          </div>
        </div>
      </header>

      {/* Main Layout */}
      <div className="flex-1 flex overflow-hidden">
        <aside className="w-64 bg-white border-r flex flex-col shadow-sm z-40">
          <nav className="flex-1 p-4 space-y-2">
            <button onClick={() => setActiveTab('config')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all ${activeTab === 'config' ? 'bg-blue-50 text-blue-600' : 'text-slate-600 hover:bg-slate-50'}`}>
              <Settings className="w-5 h-5" /> 1. 棱体误差配置
            </button>
            <button onClick={() => setActiveTab('measure')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all ${activeTab === 'measure' ? 'bg-blue-50 text-blue-600' : 'text-slate-600 hover:bg-slate-50'}`}>
              <ClipboardCheck className="w-5 h-5" /> 2. 测量数据录入
            </button>
            <button onClick={() => setActiveTab('results')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all ${activeTab === 'results' ? 'bg-blue-50 text-blue-600' : 'text-slate-600 hover:bg-slate-50'}`}>
              <BarChart3 className="w-5 h-5" /> 3. 精度评估报告
            </button>
          </nav>

          <div className="p-4 border-t bg-slate-50">
            <div className="p-3 bg-blue-50 rounded-lg border border-blue-100">
              <div className="flex items-center gap-2 mb-2 text-blue-700 font-bold text-xs uppercase">
                <AlertCircle className="w-3 h-3" /> 自动归一化已开启
              </div>
              <p className="text-[10px] text-slate-600 leading-relaxed">
                系统会自动将首个正向读数（{measurements[0].forwardReadings[0]}"）设为零位参考点。
              </p>
            </div>
          </div>
        </aside>

        <main className="flex-1 overflow-y-auto bg-slate-50 p-8">
          <div className="max-w-6xl mx-auto">
            {activeTab === 'config' && (
              <div className="space-y-6 animate-in fade-in duration-300">
                <h2 className="text-2xl font-bold text-slate-800">24面棱体检定值</h2>
                <PrismTable data={prismData} onChange={handlePrismChange} />
                <div className="flex justify-end"><button onClick={() => setActiveTab('measure')} className="px-6 py-2 bg-blue-600 text-white rounded-lg shadow flex items-center gap-2">下一步：录入测量数据 <ChevronRight className="w-4 h-4" /></button></div>
              </div>
            )}

            {activeTab === 'measure' && (
              <div className="space-y-6 animate-in fade-in duration-300">
                <h2 className="text-2xl font-bold text-slate-800">准直仪读数记录</h2>
                <MeasurementTable 
                  measurements={measurements} 
                  onChange={handleMeasurementChange} 
                  onBulkPaste={() => setShowBulkModal(true)}
                  numRuns={numRuns}
                />
                <div className="flex justify-between items-center">
                  <p className="text-sm text-slate-500 italic">提示：第一个数据不为0没关系，软件会自动进行零位偏移补偿。</p>
                  <div className="flex gap-4">
                    <button onClick={() => setActiveTab('config')} className="px-6 py-2 border rounded-lg hover:bg-white transition-colors">上一步</button>
                    <button onClick={() => setActiveTab('results')} className="px-6 py-2 bg-blue-600 text-white rounded-lg shadow">分析结果</button>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'results' && (
              <div className="space-y-8 animate-in fade-in duration-300 pb-20">
                <div className="flex justify-between items-end">
                  <h2 className="text-2xl font-bold text-slate-800">测试结果分析</h2>
                  <button onClick={handleGenerateReport} disabled={isAnalyzing} className="px-6 py-2 bg-indigo-600 text-white rounded-lg shadow-md flex items-center gap-2 disabled:opacity-50">
                    <Cpu className={`w-4 h-4 ${isAnalyzing ? 'animate-spin' : ''}`} /> {isAnalyzing ? '分析中...' : 'AI 专家诊断'}
                  </button>
                </div>
                <ResultDashboard results={results} />
                {aiReport && (
                  <div className="bg-white p-8 rounded-xl shadow-sm border-l-4 border-indigo-500 space-y-4 animate-in fade-in zoom-in-95 duration-500">
                    <div className="flex items-center gap-3 text-indigo-600"><Cpu className="w-6 h-6" /><h3 className="text-lg font-bold">计量专家 AI 报告</h3></div>
                    <div className="prose prose-slate max-w-none text-slate-700 leading-relaxed whitespace-pre-line font-medium">{aiReport}</div>
                  </div>
                )}
              </div>
            )}
          </div>
        </main>
      </div>

      {/* Bulk Import Modal */}
      {showBulkModal && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-xl shadow-2xl flex flex-col max-h-[80vh]">
            <div className="p-4 border-b flex justify-between items-center bg-slate-50 rounded-t-xl">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <ClipboardCheck className="w-5 h-5 text-blue-600" />
                批量粘贴测量数据 (支持 Excel/文本)
              </h3>
              <button onClick={() => setShowBulkModal(false)} className="p-1 hover:bg-slate-200 rounded-full transition-colors">
                <X className="w-5 h-5" />
              </button>
            </div>
            <div className="p-6 space-y-4 overflow-y-auto">
              <div className="bg-amber-50 p-3 rounded-lg border border-amber-100 text-xs text-amber-800 leading-relaxed">
                <strong>数据要求：</strong> 请按顺序复制您的测量数据。
                系统将按 <strong>[正转24面 -> 反转24面]</strong> 的顺序依次填充 {numRuns} 次测量循环。
                支持从 Excel 直接复制单列或多列数据。
              </div>
              <textarea
                value={bulkInput}
                onChange={(e) => setBulkInput(e.target.value)}
                placeholder="在此粘贴您的数据..."
                className="w-full h-64 p-4 border rounded-lg font-mono text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
            </div>
            <div className="p-4 border-t flex justify-end gap-3">
              <button onClick={() => setShowBulkModal(false)} className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg font-medium transition-colors">取消</button>
              <button 
                onClick={handleBulkImport}
                disabled={!bulkInput.trim()}
                className="px-6 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium shadow-md transition-all disabled:opacity-50"
              >
                导入并解析
              </button>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white border-t px-6 py-2 text-[10px] text-slate-400 flex justify-between uppercase tracking-widest font-mono">
        <div className="flex gap-4"><span>ISO 230-2:2014 Compliant</span><span>Zeroing: Enabled</span></div>
        <div>Metrology Suite v2.5.0</div>
      </footer>
    </div>
  );
};

