  results: ISOResult;
}

const ResultDashboard: React.FC<Props> = ({ results }) => {
  // 核心绘图数据转换
  const data = useMemo(() => {
    return results.points.map(p => ({
      angle: p.angle,
      fMean: Number(p.meanForward.toFixed(3)),
      rMean: Number(p.meanReverse.toFixed(3)),
      totalMean: Number(((p.meanForward + p.meanReverse) / 2).toFixed(3)),
      fUpper: Number((p.meanForward + 2 * p.stdForward).toFixed(3)),
      fLower: Number((p.meanForward - 2 * p.stdForward).toFixed(3)),
      rUpper: Number((p.meanReverse + 2 * p.stdReverse).toFixed(3)),
      rLower: Number((p.meanReverse - 2 * p.stdReverse).toFixed(3)),
    }));
  }, [results]);

  // 原始测量点 (x_ij)
  const scatterData = useMemo(() => {
    return results.points.flatMap(p => [
      ...p.correctedForwardRuns.map(val => ({ x: p.angle, y: Number(val.toFixed(3)), type: 'F' })),
      ...p.correctedReverseRuns.map(val => ({ x: p.angle, y: Number(val.toFixed(3)), type: 'R' }))
    ]);
  }, [results]);

  // 计算 Y 轴动态域，防止线条太细看不见
  const yDomain = useMemo(() => {
    const allVals = data.flatMap(d => [d.fUpper, d.fLower, d.rUpper, d.rLower]);
    if (allVals.length === 0) return [-1, 1];
    const max = Math.max(...allVals);
    const min = Math.min(...allVals);
    const padding = Math.max(Math.abs(max - min) * 0.2, 1); // 至少保留 1 arcsec 的视窗
    return [Math.floor(min - padding), Math.ceil(max + padding)];
  }, [data]);

  return (
    <div className="bg-white p-6 border-2 border-slate-200 shadow-2xl rounded-xl">
