          <div className="flex items-center gap-1"><span className="w-3 h-3 bg-black rounded-full"></span> 平均</div>
        </div>
      </div>

      <div className="h-[600px] w-full bg-[#fafafa] rounded-lg border border-slate-100 relative overflow-hidden">
        <ResponsiveContainer width="100%" height="100%">
          <ComposedChart data={data} margin={{ top: 40, right: 40, left: 20, bottom: 40 }}>
            <CartesianGrid strokeDasharray="2 2" stroke="#e2e8f0" vertical={true} />

            <XAxis 
              dataKey="angle" 
              type="number" 
              domain={[0, 360]} 
              ticks={[0, 45, 90, 135, 180, 225, 270, 315, 360]}
              tick={{ fontSize: 12, fill: '#1e293b', fontWeight: 'bold' }}
              axisLine={{ stroke: '#0f172a', strokeWidth: 2 }}
            >
              <Label value="目标角度 Target Position (°)" offset={-20} position="insideBottom" style={{ fontSize: '13px', fontWeight: 'bold', fill: '#475569' }} />
            </XAxis>

            <YAxis 
