              axisLine={{ stroke: '#0f172a', strokeWidth: 2 }}
              domain={yDomain}
              allowDecimals={true}
            >
              <Label value="偏差值 Deviation (arcsec)" angle={-90} position="insideLeft" offset={15} style={{ textAnchor: 'middle', fontSize: '13px', fontWeight: 'bold', fill: '#475569' }} />
            </YAxis>

            <Tooltip 
