              itemStyle={{ fontSize: '12px', padding: '2px 0' }}
            />

            <ReferenceLine y={0} stroke="#475569" strokeWidth={1} strokeDasharray="3 3" />

            {/* 原始散点 - 调低透明度防止干扰主线 */}
            <Scatter name="原始数据点" data={scatterData} fill="#94a3b8" shape="circle" fillOpacity={0.4} isAnimationActive={false} />

