              activeDot={{ r: 6 }}
              type="monotone" 
            />

            {/* 总平均偏差曲线 (黑色加粗) */}
            <Line 
              name="双向平均 (Mean)" 
              dataKey="totalMean" 
              stroke="#0f172a" 
              strokeWidth={4} 
              dot={false}
              type="monotone" 
            />
          </ComposedChart>
        </ResponsiveContainer>
      </div>

      {/* 指标卡片 - 增强视觉呈现 */}
      <div className="mt-8 grid grid-cols-2 md:grid-cols-5 gap-4">
        {[
          { label: '双向定位精度 A', val: results.A, color: 'border-blue-500 text-blue-700' },
          { label: '定位偏差 E', val: results.E, color: 'border-slate-800 text-slate-800' },
          { label: '双向重复性 R', val: results.R, color: 'border-indigo-500 text-indigo-700' },
          { label: '最大反向差 B', val: results.B, color: 'border-red-500 text-red-700' },
          { label: '平均位置差 M', val: results.M, color: 'border-emerald-500 text-emerald-700' },
        ].map((item, idx) => (
          <div key={idx} className={`p-4 rounded-xl border-l-4 bg-slate-50 shadow-sm ${item.color}`}>
            <div className="text-[10px] font-bold uppercase opacity-60 mb-1">{item.label}</div>
            <div className="text-2xl font-black font-mono">
              {item.val.toFixed(3)}<span className="text-xs ml-1">"</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ResultDashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { PrismFaceData, MeasurementPoint, ISOResult } from './types';
import PrismTable from './components/PrismTable';
import MeasurementTable from './components/MeasurementTable';
import ResultDashboard from './components/ResultDashboard';
import { calculateISO230 } from './services/isoCalculator';
import { analyzeTestResults } from './services/geminiService';
import { Settings, ClipboardCheck, BarChart3, HelpCircle, FileText, ChevronRight, Activity, Cpu, X, AlertCircle, ClipboardPaste, ArrowRightLeft, ListOrdered, Beaker } from 'lucide-react';

const NUM_FACES = 24;
const INITIAL_PRISM_DATA: PrismFaceData[] = Array.from({ length: NUM_FACES }, (_, i) => ({
  face: i + 1,
  targetAngle: i * 15,
  error: 0
}));

const INITIAL_MEASUREMENTS: (numRuns: number) => MeasurementPoint[] = (numRuns) => 
  Array.from({ length: NUM_FACES }, (_, i) => ({
    face: i + 1,
    targetAngle: i * 15,
    forwardReadings: Array(numRuns).fill(0),
    reverseReadings: Array(numRuns).fill(0)
  }));

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'config' | 'measure' | 'results'>('config');
  const [numRuns, setNumRuns] = useState(5);
  const [prismData, setPrismData] = useState<PrismFaceData[]>(INITIAL_PRISM_DATA);
  const [measurements, setMeasurements] = useState<MeasurementPoint[]>(INITIAL_MEASUREMENTS(5));
  const [aiReport, setAiReport] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const [showBulkModal, setShowBulkModal] = useState(false);
  const [showPrismModal, setShowPrismModal] = useState(false);
  const [bulkInput, setBulkInput] = useState('');
  const [prismInput, setPrismInput] = useState('');
  const [importMode, setImportMode] = useState<'cycle' | 'run'>('cycle');

  useEffect(() => {
    setMeasurements(prev => {
      return prev.map(m => ({
        ...m,
        forwardReadings: m.forwardReadings.length === numRuns ? m.forwardReadings : Array(numRuns).fill(0),
        reverseReadings: m.reverseReadings.length === numRuns ? m.reverseReadings : Array(numRuns).fill(0)
      }));
    });
  }, [numRuns]);

  const results = useMemo(() => calculateISO230(measurements, prismData), [measurements, prismData]);

  const handlePrismChange = (index: number, error: number) => {
    const newData = [...prismData];
    newData[index].error = error;
    setPrismData(newData);
  };

  const handleMeasurementChange = (faceIdx: number, type: 'forward' | 'reverse', runIdx: number, value: number) => {
    const newMeasurements = [...measurements];
    if (type === 'forward') {
      newMeasurements[faceIdx].forwardReadings[runIdx] = value;
    } else {
      newMeasurements[faceIdx].reverseReadings[runIdx] = value;
    }
    setMeasurements(newMeasurements);
  };

  // 注入专家演示数据，用于验证图表渲染
  const loadDemoData = () => {
    const demoPrism = prismData.map((d, i) => ({ ...d, error: Math.sin(i * 0.5) * 0.5 }));
    const demoMeas = measurements.map((m, i) => ({
      ...m,
      forwardReadings: m.forwardReadings.map((_, rIdx) => 10 + Math.sin(i * 0.4) * 5 + Math.random() * 0.5),
      reverseReadings: m.reverseReadings.map((_, rIdx) => 10 + Math.sin(i * 0.4) * 5 + Math.random() * 0.5 + 1.2)
    }));
    setPrismData(demoPrism);
    setMeasurements(demoMeas);
    setActiveTab('results');
  };

  const handlePrismBulkImport = () => {
    const lines = prismInput.trim().split(/\r?\n/);
    const newData = [...prismData];
    let values: number[] = [];
    lines.forEach(line => {
      const parts = line.split(/[\t, ]+/).map(p => parseFloat(p)).filter(p => !isNaN(p));
      if (parts.length > 0) values.push(parts[parts.length - 1]);
    });
    if (values.length < NUM_FACES) {
      values = prismInput.trim().split(/[\t\s\n,]+/).map(v => parseFloat(v)).filter(v => !isNaN(v));
    }
    values.slice(0, NUM_FACES).forEach((val, i) => {
      newData[i].error = val;
    });
    setPrismData(newData);
    setShowPrismModal(false);
    setPrismInput('');
  };

  const handleBulkImport = () => {
    const newMeasurements = JSON.parse(JSON.stringify(measurements));
    const allNumbers = bulkInput.trim().split(/[\t\s\n,]+/).map(v => parseFloat(v)).filter(v => !isNaN(v));
    if (allNumbers.length === 0) return;
    let index = 0;
    if (importMode === 'cycle') {
      for (let r = 0; r < numRuns; r++) {
        for (let f = 0; f < NUM_FACES; f++) {
          if (index < allNumbers.length) newMeasurements[f].forwardReadings[r] = allNumbers[index++];
        }
        for (let f = NUM_FACES - 1; f >= 0; f--) {
          if (index < allNumbers.length) newMeasurements[f].reverseReadings[r] = allNumbers[index++];
        }
      }
    } else {
      for (let r = 0; r < numRuns; r++) {
        for (let f = 0; f < NUM_FACES; f++) {
          if (index < allNumbers.length) newMeasurements[f].forwardReadings[r] = allNumbers[index++];
        }
        for (let f = 0; f < NUM_FACES; f++) {
          if (index < allNumbers.length) newMeasurements[f].reverseReadings[r] = allNumbers[index++];
        }
      }
    }
    setMeasurements(newMeasurements);
    setShowBulkModal(false);
    setBulkInput('');
  };

  const handleGenerateReport = async () => {
    setIsAnalyzing(true);
    setAiReport(null);
    try {
      const report = await analyzeTestResults(results);
      setAiReport(report);
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      <header className="bg-slate-900 text-white px-6 py-4 flex items-center justify-between shadow-lg z-50">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-blue-600 rounded-lg"><Activity className="w-6 h-6" /></div>
          <div>
            <h1 className="text-lg font-bold tracking-tight">直驱转台精度检定系统</h1>
            <p className="text-[10px] text-slate-400 uppercase tracking-widest">ISO 230-2 Professional Suite</p>
          </div>
        </div>
        <div className="flex gap-4">
          <button 
            onClick={loadDemoData}
            className="px-3 py-1.5 bg-amber-600/20 text-amber-400 hover:bg-amber-600/30 rounded border border-amber-600/50 text-xs flex items-center gap-2 transition-all"
          >
            <Beaker className="w-3 h-3" /> 加载演示数据
          </button>
          <div className="flex items-center gap-2 bg-slate-800 px-3 py-1.5 rounded border border-slate-700">
            <Settings className="w-4 h-4 text-slate-400" />
            <label className="text-xs text-slate-300">循环次数:</label>
            <select 
              value={numRuns} 
              onChange={(e) => setNumRuns(parseInt(e.target.value))}
              className="bg-transparent text-xs outline-none font-bold text-blue-400"
            >
              {[1, 2, 3, 5, 10].map(v => <option key={v} value={v} className="bg-slate-800">{v}</option>)}
            </select>
          </div>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        <aside className="w-64 bg-white border-r flex flex-col shadow-sm">
          <nav className="flex-1 p-4 space-y-2">
            {[
              { id: 'config', icon: Settings, label: '1. 棱体误差配置' },
              { id: 'measure', icon: ClipboardCheck, label: '2. 测量数据录入' },
              { id: 'results', icon: BarChart3, label: '3. 精度评估报告' },
            ].map(tab => (
              <button 
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)} 
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-semibold transition-all ${activeTab === tab.id ? 'bg-blue-600 text-white shadow-md shadow-blue-200' : 'text-slate-600 hover:bg-slate-50'}`}
              >
                <tab.icon className="w-5 h-5" /> {tab.label}
              </button>
            ))}
          </nav>
          <div className="p-4 border-t bg-slate-50">
            <div className="p-3 bg-blue-50 rounded-lg border border-blue-100 text-[10px] text-blue-800">
              <p className="font-bold mb-1">系统状态:</p>
              <p>● 数据实时同步已开启</p>
              <p>● 零位偏差修正已应用</p>
            </div>
          </div>
        </aside>

        <main className="flex-1 overflow-y-auto bg-slate-50 p-8">
          <div className="max-w-6xl mx-auto">
            {activeTab === 'config' && (
              <div className="space-y-6">
                <h2 className="text-2xl font-black text-slate-800">24面棱体修正配置</h2>
                <PrismTable data={prismData} onChange={handlePrismChange} onBulkPaste={() => setShowPrismModal(true)} />
                <div className="flex justify-end"><button onClick={() => setActiveTab('measure')} className="px-8 py-3 bg-slate-900 text-white rounded-xl shadow-lg flex items-center gap-2 hover:bg-slate-800 transition-all font-bold">进入数据录入 <ChevronRight className="w-5 h-5" /></button></div>
              </div>
            )}

            {activeTab === 'measure' && (
              <div className="space-y-6">
                <h2 className="text-2xl font-black text-slate-800">准直仪实测值录入</h2>
                <MeasurementTable measurements={measurements} onChange={handleMeasurementChange} onBulkPaste={() => setShowBulkModal(true)} numRuns={numRuns} />
                <div className="flex justify-between items-center">
                  <div className="flex items-center gap-2 text-blue-700 bg-blue-50 px-4 py-2 rounded-lg border border-blue-100"><HelpCircle className="w-4 h-4" /><p className="text-xs font-bold">建议先从 Excel 批量粘贴数据以提高效率</p></div>
                  <button onClick={() => setActiveTab('results')} className="px-10 py-3 bg-blue-600 text-white rounded-xl shadow-lg font-bold hover:bg-blue-700 transition-all">评估测量结果</button>
                </div>
              </div>
            )}

            {activeTab === 'results' && (
              <div className="space-y-8 pb-20">
                <div className="flex justify-between items-end">
                  <h2 className="text-2xl font-black text-slate-800">ISO 230-2 分析结果</h2>
                  <button onClick={handleGenerateReport} disabled={isAnalyzing} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl shadow-xl flex items-center gap-2 disabled:opacity-50 font-bold hover:bg-indigo-700 transition-all">
                    <Cpu className={`w-5 h-5 ${isAnalyzing ? 'animate-spin' : ''}`} /> {isAnalyzing ? '深度分析中...' : '计量专家 AI 诊断'}
                  </button>
                </div>
                <ResultDashboard results={results} />
                {aiReport && (
                  <div className="bg-white p-8 rounded-2xl shadow-xl border-t-8 border-indigo-600 animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <div className="flex items-center gap-3 text-indigo-700 mb-6 border-b pb-4"><Cpu className="w-7 h-7" /><h3 className="text-xl font-black">AI 计量评估报告</h3></div>
                    <div className="text-slate-700 leading-relaxed whitespace-pre-line font-medium text-sm">{aiReport}</div>
                  </div>
                )}
              </div>
            )}
          </div>
        </main>
      </div>

      {/* Modals are kept the same as before */}
      {showPrismModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-xl rounded-2xl shadow-2xl flex flex-col">
            <div className="p-5 border-b flex justify-between items-center bg-slate-50 rounded-t-2xl">
              <h3 className="font-bold text-slate-800 flex items-center gap-2"><ClipboardPaste className="w-5 h-5" /> 批量导入棱体修正值</h3>
              <button onClick={() => setShowPrismModal(false)}><X className="w-5 h-5" /></button>
            </div>
            <div className="p-6"><textarea value={prismInput} onChange={(e) => setPrismInput(e.target.value)} placeholder="粘贴 24 个数值..." className="w-full h-64 p-4 border rounded-xl font-mono text-sm bg-slate-50" /></div>
            <div className="p-4 border-t flex justify-end gap-3"><button onClick={() => setShowPrismModal(false)} className="px-4 py-2">取消</button><button onClick={handlePrismBulkImport} className="px-6 py-2 bg-slate-900 text-white rounded-xl font-bold">执行导入</button></div>
          </div>
        </div>
      )}

      {showBulkModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl flex flex-col">
            <div className="p-5 border-b flex justify-between items-center bg-slate-50 rounded-t-2xl">
