import React, { useMemo } from 'react';
import { ISOResult } from '../types';
import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer, 
  ReferenceLine, 
  Line,
  ComposedChart,
  Scatter,
  Label
} from 'recharts';

interface Props {
  results: ISOResult;
}

const ResultDashboard: React.FC<Props> = ({ results }) => {
  // 核心绘图数据
  const chartData = useMemo(() => {
    return results.points.map(p => ({
      angle: p.angle,
      fMean: Number(p.meanForward.toFixed(3)),
      rMean: Number(p.meanReverse.toFixed(3)),
      totalMean: Number(((p.meanForward + p.meanReverse) / 2).toFixed(3)),
      fUpper: Number((p.meanForward + 2 * p.stdForward).toFixed(3)),
      fLower: Number((p.meanForward - 2 * p.stdForward).toFixed(3)),
      rUpper: Number((p.meanReverse + 2 * p.stdReverse).toFixed(3)),
      rLower: Number((p.meanReverse - 2 * p.stdReverse).toFixed(3)),
    }));
  }, [results]);

  // 计算 Y 轴动态范围
  const yDomain = useMemo(() => {
    const vals = chartData.flatMap(d => [d.fUpper, d.fLower, d.rUpper, d.rLower]);
    const max = Math.max(...vals, 1);
    const min = Math.min(...vals, -1);
    const padding = (max - min) * 0.2 || 2;
    return [Math.floor(min - padding), Math.ceil(max + padding)];
  }, [chartData]);

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 border-2 border-slate-200 shadow-2xl rounded-2xl">
        <div className="flex items-center justify-between mb-8 border-b-2 border-slate-900 pb-4">
          <div>
            <h3 className="text-xl font-black text-slate-900">定位精度与重复性曲线 (ISO 230-2)</h3>
            <p className="text-[10px] text-slate-500 uppercase tracking-widest mt-1 font-mono">Accuracy & Repeatability Curve</p>
          </div>
          <div className="flex gap-4 text-[10px] font-bold">
            <div className="flex items-center gap-1.5"><span className="w-4 h-1 bg-blue-600"></span> 正向 ↑</div>
            <div className="flex items-center gap-1.5"><span className="w-4 h-1 bg-red-600 dashed" style={{ borderTop: '2px dashed red' }}></span> 反向 ↓</div>
            <div className="flex items-center gap-1.5"><span className="w-4 h-1.5 bg-slate-900"></span> 总平均</div>
          </div>
        </div>

        <div className="h-[500px] w-full bg-slate-50 rounded-xl border border-slate-100 overflow-hidden">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData} margin={{ top: 30, right: 30, left: 10, bottom: 30 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" vertical={true} />

              <XAxis 
                dataKey="angle" 
                type="number" 
                domain={[0, 360]} 
                ticks={[0, 45, 90, 135, 180, 225, 270, 315, 360]}
                tick={{ fontSize: 11, fill: '#64748b', fontWeight: 600 }}
                axisLine={{ stroke: '#0f172a', strokeWidth: 2 }}
              >
                <Label value="角度 Position (°)" offset={-15} position="insideBottom" style={{ fontSize: '12px', fontWeight: 700, fill: '#1e293b' }} />
              </XAxis>

              <YAxis 
                domain={yDomain}
                tick={{ fontSize: 11, fill: '#64748b', fontWeight: 600 }}
                axisLine={{ stroke: '#0f172a', strokeWidth: 2 }}
              >
                <Label value="偏差 Deviation (arcsec)" angle={-90} position="insideLeft" offset={10} style={{ textAnchor: 'middle', fontSize: '12px', fontWeight: 700, fill: '#1e293b' }} />
              </YAxis>

              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: '1px solid #e2e8f0', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
              />

              <ReferenceLine y={0} stroke="#475569" strokeWidth={1} />

              {/* 统计边界带 */}
              <Line dataKey="fUpper" stroke="#cbd5e1" strokeWidth={1} strokeDasharray="5 5" dot={false} type="linear" isAnimationActive={false} legendType="none" />
              <Line dataKey="fLower" stroke="#cbd5e1" strokeWidth={1} strokeDasharray="5 5" dot={false} type="linear" isAnimationActive={false} legendType="none" />
              <Line dataKey="rUpper" stroke="#cbd5e1" strokeWidth={1} strokeDasharray="5 5" dot={false} type="linear" isAnimationActive={false} legendType="none" />
              <Line dataKey="rLower" stroke="#cbd5e1" strokeWidth={1} strokeDasharray="5 5" dot={false} type="linear" isAnimationActive={false} legendType="none" />

              {/* 正向曲线 */}
              <Line 
                name="正向平均 x̅_i↑" 
                dataKey="fMean" 
                stroke="#2563eb" 
                strokeWidth={2} 
                dot={{ r: 4, fill: '#2563eb' }} 
                type="linear"
              />

              {/* 反向曲线 */}
              <Line 
                name="反向平均 x̅_i↓" 
                dataKey="rMean" 
                stroke="#dc2626" 
                strokeWidth={2} 
                strokeDasharray="4 4" 
                dot={{ r: 4, fill: '#dc2626' }} 
                type="linear"
              />

              {/* 总平均线 */}
              <Line 
                name="总平均 x̅_i" 
                dataKey="totalMean" 
                stroke="#0f172a" 
                strokeWidth={3} 
                dot={false}
                type="linear"
              />
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        <div className="mt-8 grid grid-cols-5 gap-3">
          {[
            { label: '精度 A', val: results.A },
            { label: '偏差 E', val: results.E },
            { label: '重复性 R', val: results.R },
            { label: '反向差 B', val: results.B },
            { label: '平均差 M', val: results.M },
          ].map((item, i) => (
            <div key={i} className="bg-slate-900 text-white p-4 rounded-xl text-center shadow-lg border-b-4 border-blue-500">
              <p className="text-[9px] font-bold opacity-60 uppercase mb-1">{item.label}</p>
              <p className="text-xl font-black font-mono">{item.val.toFixed(3)}<span className="text-[10px] ml-0.5">"</span></p>
            </div>
          ))}
        </div>
      </div>

      {/* 数据明细表 - 用于物理验证 */}
      <div className="bg-white rounded-xl shadow border overflow-hidden">
        <div className="bg-slate-50 px-4 py-2 border-b text-xs font-bold text-slate-500 uppercase tracking-tighter">
          计算明细 Data Points Detail
        </div>
        <div className="max-h-64 overflow-y-auto">
          <table className="w-full text-[10px] text-left">
            <thead className="bg-white sticky top-0 shadow-sm">
              <tr className="border-b">
                <th className="px-4 py-2">角度 (°)</th>
                <th className="px-4 py-2">正向平均 (")</th>
                <th className="px-4 py-2">反向平均 (")</th>
                <th className="px-4 py-2">反向差 B (")</th>
                <th className="px-4 py-2">重复性 R (")</th>
              </tr>
            </thead>
            <tbody className="divide-y font-mono">
              {results.points.map((p, i) => (
                <tr key={i} className="hover:bg-blue-50/50">
                  <td className="px-4 py-1.5 font-bold text-slate-700">{p.angle}°</td>
                  <td className="px-4 py-1.5 text-blue-600">{p.meanForward.toFixed(3)}</td>
                  <td className="px-4 py-1.5 text-red-600">{p.meanReverse.toFixed(3)}</td>
                  <td className="px-4 py-1.5">{p.reversalError.toFixed(3)}</td>
                  <td className="px-4 py-1.5">{(Math.max(4*p.stdForward, 4*p.stdReverse)).toFixed(3)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ResultDashboard;

