    const padding = Math.max((max - min) * 0.2, 2);
    return [Math.floor(min - padding), Math.ceil(max + padding)];
  }, [chartData]);

  const exportToCSV = () => {
    const headers = ['Target Angle (°)', 'Mean Forward (")', 'Mean Reverse (")', 'Reversal Error B (")', 'Repeatability R (")'];
    const rows = results.points.map(p => [
      p.angle,
      p.meanForward.toFixed(3),
      p.meanReverse.toFixed(3),
      p.reversalError.toFixed(3),
      Math.max(4 * p.stdForward, 4 * p.stdReverse).toFixed(3)
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(','), ...rows.map(r => r.join(','))].join('\n');

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `ISO230_Test_Report_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
