            >
              <Printer className="w-4 h-4" /> 打印报告
            </button>
          </div>
        </div>

        <div className="h-[500px] w-full bg-white rounded-xl overflow-hidden border border-slate-50">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData} margin={{ top: 30, right: 30, left: 10, bottom: 30 }}>
