              </YAxis>

              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: '1px solid #e2e8f0', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
              />

              <ReferenceLine y={0} stroke="#475569" strokeWidth={1} />

              <Line name="正向带 (+2σ)" dataKey="fUpper" stroke="#e2e8f0" strokeWidth={1} strokeDasharray="5 5" dot={false} type="linear" isAnimationActive={false} />
              <Line name="正向带 (-2σ)" dataKey="fLower" stroke="#e2e8f0" strokeWidth={1} strokeDasharray="5 5" dot={false} type="linear" isAnimationActive={false} />

              <Line 
                name="正向平均 x̅_i↑" 
                dataKey="fMean" 
                stroke="#2563eb" 
                strokeWidth={2} 
                dot={{ r: 4, fill: '#2563eb', strokeWidth: 0 }} 
                type="linear"
              />

              <Line 
                name="反向平均 x̅_i↓" 
                dataKey="rMean" 
                stroke="#dc2626" 
                strokeWidth={2} 
                strokeDasharray="4 4" 
                dot={{ r: 4, fill: '#dc2626', strokeWidth: 0 }} 
                type="linear"
              />

              <Line 
                name="总平均误差 x̅_i" 
                dataKey="totalMean" 
                stroke="#0f172a" 
                strokeWidth={3} 
                dot={false}
                type="linear"
              />
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        <div className="mt-8 grid grid-cols-5 gap-3">
          {[
            { label: '双向定位精度 A', val: results.A, sub: 'Bi-dir Accuracy' },
            { label: '定位偏差 E', val: results.E, sub: 'Systematic Error' },
