import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  ReferenceLine, 
  Line,
  ComposedChart,
  Label
} from 'recharts';
import { Printer, FileSpreadsheet } from 'lucide-react';

interface Props {
  results: ISOResult;
}

const ResultDashboard: React.FC<Props> = ({ results }) => {
  // 获取测量循环次数
  const numRuns = results.points[0]?.correctedForwardRuns.length || 0;

  // 构建包含所有 Run 数据点的图表数据集
  const chartData = useMemo(() => {
    return results.points.map(p => {
      const dataPoint: any = {
        angle: p.angle,
        fUpper: Number((p.meanForward + 2 * p.stdForward).toFixed(3)),
        fLower: Number((p.meanForward - 2 * p.stdForward).toFixed(3)),
        rUpper: Number((p.meanReverse + 2 * p.stdReverse).toFixed(3)),
        rLower: Number((p.meanReverse - 2 * p.stdReverse).toFixed(3)),
      };

      // 动态注入每一轮的正向和反向读数
      p.correctedForwardRuns.forEach((val, idx) => {
        dataPoint[`fRun${idx}`] = Number(val.toFixed(3));
      });
      p.correctedReverseRuns.forEach((val, idx) => {
        dataPoint[`rRun${idx}`] = Number(val.toFixed(3));
      });

      return dataPoint;
    });
  }, [results]);

  const yDomain = useMemo(() => {
    const allVals: number[] = [];
    results.points.forEach(p => {
      allVals.push(...p.correctedForwardRuns, ...p.correctedReverseRuns);
    });
    const max = Math.max(...allVals, 1);
    const min = Math.min(...allVals, -1);
    const padding = Math.max((max - min) * 0.2, 2);
    return [Math.floor(min - padding), Math.ceil(max + padding)];
  }, [results]);

  const exportToCSV = () => {
    const headers = ['Target Angle (°)', ...Array.from({length: numRuns}, (_, i) => `Forward R${i+1} (")`), ...Array.from({length: numRuns}, (_, i) => `Reverse R${i+1} (")`)];
    const rows = results.points.map(p => [
      p.angle,
      ...p.correctedForwardRuns.map(v => v.toFixed(3)),
      ...p.correctedReverseRuns.map(v => v.toFixed(3))
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(','), ...rows.map(r => r.join(','))].join('\n');

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `ISO230_FullData_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 border-2 border-slate-200 shadow-2xl rounded-2xl relative">
        <div className="flex items-center justify-between mb-8 border-b-2 border-slate-900 pb-4">
          <div>
            <h3 className="text-xl font-black text-slate-900">全行程实测点分布图 (ISO 230-2)</h3>
            <p className="text-[10px] text-slate-500 uppercase tracking-widest mt-1 font-mono">Full Measurement Point Distribution</p>
          </div>
          <div className="flex gap-2 no-print">
            <button 
              onClick={exportToCSV}
              className="flex items-center gap-2 px-3 py-1.5 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg text-xs font-bold transition-all border border-slate-200"
            >
              <FileSpreadsheet className="w-4 h-4" /> 导出原始点
            </button>
            <button 
              onClick={() => window.print()}
              className="flex items-center gap-2 px-3 py-1.5 bg-slate-900 hover:bg-slate-800 text-white rounded-lg text-xs font-bold transition-all shadow-md"
            >
              <Printer className="w-4 h-4" /> 打印报告
            </button>
          </div>
        </div>

        <div className="h-[550px] w-full bg-white rounded-xl overflow-hidden">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData} margin={{ top: 30, right: 30, left: 10, bottom: 30 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" vertical={true} />

              <XAxis 
                dataKey="angle" 
                type="number" 
                domain={[0, 360]} 
                ticks={[0, 45, 90, 135, 180, 225, 270, 315, 360]}
                tick={{ fontSize: 11, fill: '#64748b', fontWeight: 600 }}
                axisLine={{ stroke: '#0f172a', strokeWidth: 2 }}
              >
                <Label value="目标角度 Target Position (°)" offset={-15} position="insideBottom" style={{ fontSize: '12px', fontWeight: 700, fill: '#1e293b' }} />
              </XAxis>

              <YAxis 
                domain={yDomain}
                tick={{ fontSize: 11, fill: '#64748b', fontWeight: 600 }}
                axisLine={{ stroke: '#0f172a', strokeWidth: 2 }}
              >
                <Label value="偏差 Deviation (arcsec)" angle={-90} position="insideLeft" offset={10} style={{ textAnchor: 'middle', fontSize: '12px', fontWeight: 700, fill: '#1e293b' }} />
              </YAxis>

              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: '1px solid #e2e8f0', fontSize: '12px' }}
                cursor={{ stroke: '#e2e8f0', strokeWidth: 1 }}
              />

              <ReferenceLine y={0} stroke="#475569" strokeWidth={1} />

              {/* 置信区间背景带 */}
              <Line dataKey="fUpper" stroke="#f1f5f9" strokeWidth={1} strokeDasharray="5 5" dot={false} type="linear" isAnimationActive={false} />
              <Line dataKey="fLower" stroke="#f1f5f9" strokeWidth={1} strokeDasharray="5 5" dot={false} type="linear" isAnimationActive={false} />

              {/* 绘制所有正向 Run 数据点和连接线 */}
              {Array.from({ length: numRuns }).map((_, idx) => (
                <Line
                  key={`fRun${idx}`}
                  name={`正向 R${idx + 1}`}
                  dataKey={`fRun${idx}`}
                  stroke="#2563eb"
                  strokeWidth={1}
                  strokeOpacity={0.3}
                  dot={{ r: 3, fill: '#2563eb', strokeWidth: 0, fillOpacity: 0.8 }}
                  type="linear"
                  isAnimationActive={false}
                />
              ))}

              {/* 绘制所有反向 Run 数据点和连接线 */}
              {Array.from({ length: numRuns }).map((_, idx) => (
                <Line
                  key={`rRun${idx}`}
                  name={`反向 R${idx + 1}`}
                  dataKey={`rRun${idx}`}
                  stroke="#dc2626"
                  strokeWidth={1}
                  strokeOpacity={0.3}
                  strokeDasharray="3 3"
                  dot={{ r: 3, fill: '#dc2626', strokeWidth: 0, fillOpacity: 0.8 }}
                  type="linear"
                  isAnimationActive={false}
                />
              ))}
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        <div className="mt-8 flex flex-wrap gap-4 justify-center bg-slate-50 p-4 rounded-xl">
           <div className="flex items-center gap-2"><span className="w-3 h-3 rounded-full bg-blue-600"></span> <span className="text-xs font-bold text-slate-600">正向行程点 (Forward)</span></div>
           <div className="flex items-center gap-2"><span className="w-3 h-3 rounded-full bg-red-600"></span> <span className="text-xs font-bold text-slate-600">反向行程点 (Reverse)</span></div>
           <div className="flex items-center gap-2"><span className="w-8 h-px border-t border-dashed border-slate-300"></span> <span className="text-xs text-slate-400">各测量批次路径</span></div>
        </div>

        <div className="mt-8 grid grid-cols-5 gap-3">
          {[
            { label: '精度 A', val: results.A },
            { label: '偏差 E', val: results.E },
            { label: '重复性 R', val: results.R },
            { label: '反向差 B', val: results.B },
            { label: '平均差 M', val: results.M },
          ].map((item, i) => (
            <div key={i} className="bg-slate-900 text-white p-4 rounded-xl text-center shadow-lg">
              <p className="text-[9px] font-bold opacity-60 uppercase mb-1">{item.label}</p>
              <p className="text-xl font-black font-mono">{item.val.toFixed(3)}<span className="text-[10px] ml-0.5">"</span></p>
            </div>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-xl shadow border overflow-hidden">
        <div className="bg-slate-50 px-4 py-2.5 border-b text-xs font-bold text-slate-500 uppercase tracking-tighter">
          原始测量点矩阵 Raw Data Matrix
        </div>
        <div className="max-h-80 overflow-y-auto">
          <table className="w-full text-[10px] text-left border-collapse">
            <thead className="bg-slate-50 sticky top-0 z-10">
              <tr className="border-b">
                <th className="px-3 py-2 border-r font-bold w-16">角度</th>
                {Array.from({ length: numRuns }).map((_, i) => (
                  <th key={`th-f-${i}`} className="px-2 py-2 border-r text-blue-700 bg-blue-50/30">正向 R{i+1}</th>
                ))}
                {Array.from({ length: numRuns }).map((_, i) => (
                  <th key={`th-r-${i}`} className="px-2 py-2 border-r text-red-700 bg-red-50/30">反向 R{i+1}</th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y font-mono">
              {results.points.map((p, i) => (
                <tr key={i} className="hover:bg-slate-50">
                  <td className="px-3 py-1.5 border-r font-bold bg-slate-50/50">{p.angle}°</td>
                  {p.correctedForwardRuns.map((v, idx) => (
                    <td key={`td-f-${idx}`} className="px-2 py-1.5 border-r text-blue-600/80">{v.toFixed(3)}</td>
                  ))}
                  {p.correctedReverseRuns.map((v, idx) => (
                    <td key={`td-r-${idx}`} className="px-2 py-1.5 border-r text-red-600/80">{v.toFixed(3)}</td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ResultDashboard;

import React, { useMemo } from 'react';
import { ISOResult } from '../types';
import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
