                const style = RUN_STYLES[idx % RUN_STYLES.length];
                return (
                  <Line
                    key={`fRun${idx}`}
                    name={`正向行程 Run ${idx + 1}`}
                    dataKey={`fRun${idx}`}
                    stroke={FORWARD_COLORS[idx % FORWARD_COLORS.length]}
                    strokeWidth={style.strokeWidth}
                    strokeDasharray={style.dash}
                    dot={{ r: 4, fill: FORWARD_COLORS[idx % FORWARD_COLORS.length], strokeWidth: 1, stroke: 'white' }}
                    activeDot={{ r: 6, strokeWidth: 0 }}
                    type="linear"
                    isAnimationActive={false}
                  />
