          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-y-4 gap-x-8">
            {Array.from({ length: numRuns }).map((_, idx) => {
              const style = RUN_STYLES[idx % RUN_STYLES.length];
              return (
                <div key={`legend-${idx}`} className="flex flex-col gap-2 p-2 rounded-lg hover:bg-white transition-colors">
                  <div className="flex items-center justify-between text-[11px] font-bold">
                    <span className="text-slate-700">第 {idx + 1} 次测量 (Run {idx+1})</span>
                    <span className="text-[9px] text-slate-400 font-normal uppercase">{style.label}</span>
                  </div>
                  <div className="flex items-center gap-4">
                    <div className="flex-1 flex items-center gap-2">
                      <div 
                        className="h-1 flex-1 rounded" 
                        style={{ 
                          backgroundColor: FORWARD_COLORS[idx % FORWARD_COLORS.length],
                          borderTop: `${style.strokeWidth}px ${style.dash === '0' ? 'solid' : 'dashed'} ${FORWARD_COLORS[idx % FORWARD_COLORS.length]}`
                        }}
                      />
                      <span className="text-[9px] text-blue-600 font-mono">↑ 正向</span>
                    </div>
                    <div className="flex-1 flex items-center gap-2">
                      <div 
                        className="h-1 flex-1 rounded" 
                        style={{ 
                          backgroundColor: REVERSE_COLORS[idx % REVERSE_COLORS.length],
                          borderTop: `${style.strokeWidth}px ${style.dash === '0' ? 'solid' : 'dashed'} ${REVERSE_COLORS[idx % REVERSE_COLORS.length]}`
                        }}
                      />
                      <span className="text-[9px] text-red-600 font-mono">↓ 反向</span>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* 关键指标看板 */}
        <div className="mt-8 grid grid-cols-5 gap-3">
          {[
            { label: '双向定位精度 A', val: results.A, color: 'border-blue-500' },
            { label: '定位系统偏差 E', val: results.E, color: 'border-slate-400' },
            { label: '单向重复性 R', val: results.R, color: 'border-indigo-500' },
            { label: '最大反向差 B', val: results.B, color: 'border-red-500' },
            { label: '平均偏差 M', val: results.M, color: 'border-emerald-500' },
          ].map((item, i) => (
            <div key={i} className={`bg-white border-t-4 ${item.color} p-4 rounded-xl text-center shadow-md`}>
              <p className="text-[9px] font-bold text-slate-500 uppercase mb-1">{item.label}</p>
              <p className="text-xl font-black font-mono text-slate-900">{item.val.toFixed(3)}<span className="text-[10px] ml-0.5">"</span></p>
            </div>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-xl shadow border overflow-hidden no-print">
        <div className="bg-slate-50 px-4 py-2.5 border-b flex justify-between items-center">
          <div className="text-xs font-bold text-slate-500 uppercase tracking-tighter">
            实测数据点矩阵 (归零修正后)
          </div>
          <div className="text-[10px] text-slate-400">
            修正公式: V_corrected = (V_measured - V_zero) + V_prism
          </div>
        </div>
        <div className="max-h-80 overflow-y-auto overflow-x-auto">
          <table className="w-full text-[10px] text-left border-collapse">
            <thead className="bg-slate-50 sticky top-0 z-10">
              <tr className="border-b">
                <th className="px-3 py-2 border-r font-bold w-16 bg-white">角度</th>
                {Array.from({ length: numRuns }).map((_, i) => (
                  <th key={`th-f-${i}`} className="px-2 py-2 border-r text-blue-700 font-bold">正向 R{i+1}</th>
                ))}
                {Array.from({ length: numRuns }).map((_, i) => (
                  <th key={`th-r-${i}`} className="px-2 py-2 border-r text-red-700 font-bold">反向 R{i+1}</th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y font-mono">
              {results.points.map((p, i) => (
                <tr key={i} className="hover:bg-blue-50/30 transition-colors">
                  <td className="px-3 py-1.5 border-r font-bold bg-slate-50/50">{p.angle}°</td>
                  {p.correctedForwardRuns.map((v, idx) => (
                    <td key={`td-f-${idx}`} className="px-2 py-1.5 border-r text-blue-600/70">{v.toFixed(3)}</td>
                  ))}
                  {p.correctedReverseRuns.map((v, idx) => (
                    <td key={`td-r-${idx}`} className="px-2 py-1.5 border-r text-red-600/70">{v.toFixed(3)}</td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ResultDashboard;

