// 定义不同循环的视觉样式：粗细、虚实
const RUN_STYLES = [
  { strokeWidth: 3, dash: "0", label: "厚实线 (Primary)", weight: "font-black" },
  { strokeWidth: 2, dash: "6 4", label: "标准虚线 (Dashed)", weight: "font-bold" },
  { strokeWidth: 1.5, dash: "2 3", label: "细点线 (Dotted)", weight: "font-medium" },
  { strokeWidth: 2, dash: "12 4 2 4", label: "点划线 (Chain)", weight: "font-medium" },
  { strokeWidth: 1.2, dash: "1 4", label: "极细点线 (Hairline)", weight: "font-normal" },
];

const FORWARD_COLORS = ['#1e40af', '#2563eb', '#3b82f6', '#60a5fa', '#93c5fd'];
const REVERSE_COLORS = ['#991b1b', '#dc2626', '#ef4444', '#f87171', '#fca5a5'];

const ResultDashboard: React.FC<Props> = ({ results }) => {
  const numRuns = results.points[0]?.correctedForwardRuns.length || 0;

  const chartData = useMemo(() => {
    return results.points.map(p => {
      const dataPoint: any = {
        angle: p.angle,
        fUpper: Number((p.meanForward + 2 * p.stdForward).toFixed(3)),
        fLower: Number((p.meanForward - 2 * p.stdForward).toFixed(3)),
      };
      p.correctedForwardRuns.forEach((val, idx) => { dataPoint[`fRun${idx}`] = Number(val.toFixed(3)); });
      p.correctedReverseRuns.forEach((val, idx) => { dataPoint[`rRun${idx}`] = Number(val.toFixed(3)); });
      return dataPoint;
    });
  }, [results, numRuns]);

  // 优化后的坐标轴算法：根据数据极值动态收紧
  const yDomain = useMemo(() => {
    const allVals: number[] = [];
    results.points.forEach(p => {
      allVals.push(...p.correctedForwardRuns, ...p.correctedReverseRuns);
    });
    if (allVals.length === 0) return [-5, 5];

    const max = Math.max(...allVals);
    const min = Math.min(...allVals);
    const range = max - min;

    // 增加 15% 的动态留白，保证 0 位附近始终有呼吸感，且不会因为数据极小导致坐标轴撑得太大
    const padding = range === 0 ? 1 : Math.max(range * 0.15, 0.2); 

    // 确保坐标轴至少覆盖 [-0.5, 0.5] 以免视觉过于局促
    return [
      Math.min(min - padding, -0.5),
      Math.max(max + padding, 0.5)
    ];
  }, [results]);

  const exportToCSV = () => {
    const headers = ['Target Angle (°)', ...Array.from({length: numRuns}, (_, i) => `Forward R${i+1} (")`), ...Array.from({length: numRuns}, (_, i) => `Reverse R${i+1} (")`)];
    const rows = results.points.map(p => [
      p.angle,
      ...p.correctedForwardRuns.map(v => v.toFixed(3)),
      ...p.correctedReverseRuns.map(v => v.toFixed(3))
    ]);
    const csvContent = "data:text/csv;charset=utf-8,\uFEFF" + [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", `Rotary_Table_ISO230_Report.csv`);
    link.click();
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 border-2 border-slate-200 shadow-2xl rounded-2xl">
        <div className="flex items-center justify-between mb-6 border-b-2 border-slate-900 pb-4">
          <div>
            <h3 className="text-xl font-black text-slate-900">多循环误差分布轨迹图 (ISO 230-2)</h3>
            <p className="text-[10px] text-slate-500 uppercase tracking-widest mt-1 font-mono">Dynamic Multi-Trace Accuracy Analysis</p>
          </div>
          <div className="flex gap-2 no-print">
            <button onClick={exportToCSV} className="flex items-center gap-2 px-3 py-1.5 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg text-xs font-bold transition-all border border-slate-200">
              <FileSpreadsheet className="w-4 h-4" /> 导出数据
            </button>
            <button onClick={() => window.print()} className="flex items-center gap-2 px-3 py-1.5 bg-slate-900 hover:bg-slate-800 text-white rounded-lg text-xs font-bold transition-all shadow-md">
              <Printer className="w-4 h-4" /> 打印报告
            </button>
          </div>
        </div>

        {/* 核心图表区域 */}
        <div className="h-[500px] w-full bg-slate-50/30 rounded-xl p-2 border border-slate-100">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData} margin={{ top: 20, right: 30, left: 10, bottom: 40 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" vertical={true} />
              <XAxis 
                dataKey="angle" 
                type="number" 
                domain={[0, 360]} 
                ticks={[0, 45, 90, 135, 180, 225, 270, 315, 360]}
                tick={{ fontSize: 11, fill: '#64748b', fontWeight: 600 }}
                axisLine={{ stroke: '#0f172a', strokeWidth: 2 }}
              >
                <Label value="角度位置 Target Angle (°)" offset={-20} position="insideBottom" style={{ fontSize: '12px', fontWeight: 700, fill: '#1e293b' }} />
              </XAxis>
              <YAxis 
                domain={yDomain}
                tick={{ fontSize: 11, fill: '#64748b', fontWeight: 600 }}
                axisLine={{ stroke: '#0f172a', strokeWidth: 2 }}
              >
                <Label value="偏差 Deviation (arcsec)" angle={-90} position="insideLeft" offset={10} style={{ textAnchor: 'middle', fontSize: '12px', fontWeight: 700, fill: '#1e293b' }} />
              </YAxis>

              <Tooltip 
                contentStyle={{ borderRadius: '12px', border: 'none', fontSize: '11px', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' }}
              />

              <ReferenceLine y={0} stroke="#475569" strokeWidth={2} label={{ position: 'right', value: 'REF', fontSize: 10, fill: '#94a3b8', fontWeight: 'bold' }} />

              {/* 动态渲染所有正向测量序列 */}
              {Array.from({ length: numRuns }).map((_, idx) => {
                const style = RUN_STYLES[idx % RUN_STYLES.length];
                return (
                  <Line
                    key={`fRun${idx}`}
                    name={`正向 R${idx + 1}`}
                    dataKey={`fRun${idx}`}
                    stroke={FORWARD_COLORS[idx % FORWARD_COLORS.length]}
                    strokeWidth={style.strokeWidth}
                    strokeDasharray={style.dash}
                    dot={{ r: 3, fill: FORWARD_COLORS[idx % FORWARD_COLORS.length], strokeWidth: 1, stroke: 'white' }}
                    activeDot={{ r: 5 }}
                    type="linear"
                    isAnimationActive={false}
                  />
                );
              })}

              {/* 动态渲染所有反向测量序列 */}
              {Array.from({ length: numRuns }).map((_, idx) => {
                const style = RUN_STYLES[idx % RUN_STYLES.length];
                return (
                  <Line
                    key={`rRun${idx}`}
                    name={`反向 R${idx + 1}`}
                    dataKey={`rRun${idx}`}
                    stroke={REVERSE_COLORS[idx % REVERSE_COLORS.length]}
                    strokeWidth={style.strokeWidth}
                    strokeDasharray={style.dash}
                    dot={{ r: 3, fill: REVERSE_COLORS[idx % REVERSE_COLORS.length], strokeWidth: 1, stroke: 'white' }}
                    activeDot={{ r: 5 }}
                    type="linear"
                    isAnimationActive={false}
                  />
                );
              })}
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        {/* 底部详细图例卡片 */}
        <div className="mt-8 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 bg-slate-50 p-6 rounded-2xl border border-slate-100">
          <div className="col-span-full flex items-center gap-2 mb-2 text-slate-500">
            <Info className="w-4 h-4" />
            <span className="text-[10px] font-bold uppercase tracking-widest">测量循环样式定义 Legend & Line Config</span>
          </div>
          {Array.from({ length: numRuns }).map((_, idx) => {
            const style = RUN_STYLES[idx % RUN_STYLES.length];
            return (
              <div key={`legend-${idx}`} className="bg-white p-3 rounded-xl border border-slate-200 shadow-sm flex flex-col gap-2">
                <div className="flex justify-between items-center border-b pb-1.5 border-slate-100">
                  <span className={`text-xs ${style.weight} text-slate-800`}>测量循环 {idx + 1}</span>
                  <span className="text-[9px] text-slate-400 font-mono uppercase">{style.label}</span>
                </div>
                <div className="flex items-center gap-3">
                  <div className="flex-1 space-y-1">
                    <div className="flex items-center justify-between text-[10px]">
                      <span className="text-blue-600 font-bold flex items-center gap-1"><ArrowUpRight className="w-3 h-3" />正向</span>
                      <span className="text-slate-400">{FORWARD_COLORS[idx % FORWARD_COLORS.length]}</span>
                    </div>
                    <div 
                      className="h-1.5 rounded-full" 
                      style={{ 
                        borderTop: `${style.strokeWidth}px ${style.dash === '0' ? 'solid' : 'dashed'} ${FORWARD_COLORS[idx % FORWARD_COLORS.length]}`
                      }}
                    />
                  </div>
                  <div className="flex-1 space-y-1">
                    <div className="flex items-center justify-between text-[10px]">
                      <span className="text-red-600 font-bold flex items-center gap-1"><ArrowDownRight className="w-3 h-3" />反向</span>
                      <span className="text-slate-400">{REVERSE_COLORS[idx % REVERSE_COLORS.length]}</span>
                    </div>
                    <div 
                      className="h-1.5 rounded-full" 
                      style={{ 
                        borderTop: `${style.strokeWidth}px ${style.dash === '0' ? 'solid' : 'dashed'} ${REVERSE_COLORS[idx % REVERSE_COLORS.length]}`
                      }}
                    />
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* 关键统计看板 */}
        <div className="mt-8 grid grid-cols-2 md:grid-cols-5 gap-3">
          {[
            { label: '双向精度 A', val: results.A, color: 'text-blue-600' },
            { label: '系统偏差 E', val: results.E, color: 'text-slate-600' },
            { label: '重复性 R', val: results.R, color: 'text-indigo-600' },
            { label: '反向差 B', val: results.B, color: 'text-red-600' },
            { label: '平均偏差 M', val: results.M, color: 'text-emerald-600' },
          ].map((item, i) => (
            <div key={i} className="bg-white border border-slate-200 p-4 rounded-xl text-center shadow-sm">
              <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">{item.label}</p>
              <p className={`text-2xl font-black font-mono ${item.color}`}>{item.val.toFixed(3)}<span className="text-xs ml-0.5">"</span></p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

