const INITIAL_MEASUREMENTS: (numRuns: number) => MeasurementPoint[] = (numRuns) => 
  Array.from({ length: NUM_FACES }, (_, i) => ({
    face: i + 1,
    targetAngle: i * 15,
    forwardReadings: Array(numRuns).fill(0),
    reverseReadings: Array(numRuns).fill(0)
  }));

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'config' | 'measure' | 'results'>('config');
  const [numRuns, setNumRuns] = useState(5);
  const [prismData, setPrismData] = useState<PrismFaceData[]>(INITIAL_PRISM_DATA);
  const [measurements, setMeasurements] = useState<MeasurementPoint[]>(INITIAL_MEASUREMENTS(5));
  const [aiReport, setAiReport] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showBulkModal, setShowBulkModal] = useState(false);
  const [bulkInput, setBulkInput] = useState('');

  useEffect(() => {
    setMeasurements(prev => prev.map(m => ({
      ...m,
      forwardReadings: m.forwardReadings.length === numRuns ? [...m.forwardReadings] : Array(numRuns).fill(0),
      reverseReadings: m.reverseReadings.length === numRuns ? [...m.reverseReadings] : Array(numRuns).fill(0)
    })));
  }, [numRuns]);

  const results = useMemo(() => calculateISO230(measurements, prismData), [measurements, prismData]);

  const handlePrismChange = (index: number, error: number) => {
    setPrismData(prev => {
      const next = [...prev];
      next[index] = { ...next[index], error };
      return next;
    });
  };

  const handleMeasurementChange = (faceIdx: number, type: 'forward' | 'reverse', runIdx: number, value: number) => {
    setMeasurements(prev => prev.map((m, idx) => {
      if (idx === faceIdx) {
        const newM = { ...m };
        if (type === 'forward') {
          const newF = [...m.forwardReadings];
          newF[runIdx] = value;
          newM.forwardReadings = newF;
        } else {
          const newR = [...m.reverseReadings];
          newR[runIdx] = value;
          newM.reverseReadings = newR;
        }
        return newM;
      }
      return m;
    }));
  };

  const loadDemoData = () => {
    const demoPrism = prismData.map((d, i) => ({ ...d, error: Number((Math.sin(i * 0.5) * 0.5).toFixed(2)) }));
    const demoMeas = measurements.map((m, i) => ({
      ...m,
      forwardReadings: m.forwardReadings.map(() => Number((10 + Math.sin(i * 0.4) * 5 + Math.random() * 0.5).toFixed(2))),
      reverseReadings: m.reverseReadings.map(() => Number((11 + Math.sin(i * 0.4) * 5 + Math.random() * 0.5).toFixed(2)))
    }));
    setPrismData(demoPrism);
    setMeasurements(demoMeas);
    setActiveTab('results');
  };

  const handleGenerateReport = async () => {
    setIsAnalyzing(true);
    setAiReport(null);
    try {
      const report = await analyzeTestResults(results);
      setAiReport(report);
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="h-screen flex flex-col overflow-hidden bg-slate-950">
      {/* 顶部主导航栏 - 磨砂效果 */}
      <header className="h-16 flex-shrink-0 flex items-center justify-between px-8 bg-slate-900/50 backdrop-blur-md border-b border-slate-800 z-50">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-cyan-500 rounded-xl flex items-center justify-center shadow-lg shadow-cyan-500/20">
            <Zap className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-lg font-extrabold tracking-tight text-white flex items-center gap-2">
              PRECISION <span className="text-cyan-400 font-light tracking-widest">METROLOGY</span>
            </h1>
            <div className="flex items-center gap-2 text-[9px] font-bold text-slate-500 uppercase tracking-widest">
              <ShieldCheck className="w-3 h-3 text-emerald-500" /> ISO 230-2 Verified Environment
            </div>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3 bg-slate-800/80 px-4 py-1.5 rounded-full border border-slate-700/50">
            <Layers className="w-4 h-4 text-cyan-400" />
            <span className="text-xs text-slate-400 font-bold">测量批次:</span>
            <select 
              value={numRuns} 
              onChange={(e) => setNumRuns(parseInt(e.target.value))}
              className="bg-transparent text-sm font-black text-white outline-none cursor-pointer hover:text-cyan-400 transition-colors"
            >
              {[1, 2, 3, 5, 10].map(v => <option key={v} value={v} className="bg-slate-900">{v} Runs</option>)}
            </select>
          </div>
          <button 
            onClick={loadDemoData}
            className="px-4 py-2 bg-indigo-500/10 text-indigo-400 hover:bg-indigo-500/20 rounded-xl border border-indigo-500/30 text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2"
          >
            <Beaker className="w-3 h-3" /> 运行演示仿真
          </button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* 左侧功能导航 */}
        <aside className="w-72 flex-shrink-0 bg-slate-900/30 border-r border-slate-800 p-6 flex flex-col gap-8 overflow-y-auto no-print">
          <div className="space-y-1">
            <p className="px-4 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">检定工作流</p>
            {[
              { id: 'config', icon: Database, label: '棱体修正值', sub: 'Prism Correction' },
              { id: 'measure', icon: ClipboardCheck, label: '数据流录入', sub: 'Data Acquisition' },
              { id: 'results', icon: BarChart3, label: '精度评估中心', sub: 'Quality Analytics' },
            ].map(tab => (
