              </div>
            </div>
          </div>
        </aside>

        {/* 主内容显示区域 */}
        <main className="flex-1 overflow-y-auto bg-[#020617] p-10 custom-scroll">
          <div className="max-w-6xl mx-auto">
            {activeTab === 'config' && (
