                      step="0.01"
                      value={val}
                      onChange={(e) => onChange(faceIdx, 'reverse', runIdx, parseFloat(e.target.value) || 0)}
                      className="w-full px-2 py-1 bg-transparent border-0 focus:ring-1 focus:ring-rose-500/50 rounded text-center font-mono text-rose-400/80 font-bold focus:text-white transition-all outline-none"
                    />
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

