import React, { useMemo } from 'react';
import { ISOResult } from '../types';
import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  ReferenceLine, 
  Line,
  ComposedChart,
  Label
} from 'recharts';
import { Printer, FileSpreadsheet, Info } from 'lucide-react';

interface Props {
  results: ISOResult;
}

const FORWARD_COLOR = '#1e40af'; // 深蓝
const REVERSE_COLOR = '#b91c1c'; // 深红

const ResultDashboard: React.FC<Props> = ({ results }) => {
  const numRuns = results.points[0]?.correctedForwardRuns.length || 0;

  const chartData = useMemo(() => {
    return results.points.map(p => {
      const dataPoint: any = {
        angle: p.angle,
        meanF: Number(p.meanForward.toFixed(3)),
        meanR: Number(p.meanReverse.toFixed(3)),
      };
      p.correctedForwardRuns.forEach((val, idx) => { dataPoint[`fRun${idx}`] = Number(val.toFixed(3)); });
      p.correctedReverseRuns.forEach((val, idx) => { dataPoint[`rRun${idx}`] = Number(val.toFixed(3)); });
      return dataPoint;
    });
  }, [results, numRuns]);

  // 保留用户满意的动态缩放算法
  const yDomain = useMemo(() => {
    const allVals: number[] = [];
    results.points.forEach(p => {
      allVals.push(...p.correctedForwardRuns, ...p.correctedReverseRuns);
    });
    if (allVals.length === 0) return [-5, 5];
    const max = Math.max(...allVals);
    const min = Math.min(...allVals);
    const range = max - min;
    const padding = range === 0 ? 1 : Math.max(range * 0.2, 0.5); 
    return [Math.min(min - padding, -1), Math.max(max + padding, 1)];
  }, [results]);

  return (
    <div className="space-y-6">
      {/* 核心指标看板 */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
        {[
          { label: '双向定位精度 A', val: results.A, color: 'text-blue-700', bg: 'bg-blue-50' },
          { label: '定位偏差 E', val: results.E, color: 'text-slate-700', bg: 'bg-slate-50' },
          { label: '双向重复精度 R', val: results.R, color: 'text-indigo-700', bg: 'bg-indigo-50' },
          { label: '反向差值 B', val: results.B, color: 'text-red-700', bg: 'bg-red-50' },
          { label: '平均偏差 M', val: results.M, color: 'text-emerald-700', bg: 'bg-emerald-50' },
        ].map((item, i) => (
          <div key={i} className={`${item.bg} border border-slate-200 p-4 rounded-lg shadow-sm`}>
            <p className="text-[10px] font-bold text-slate-500 uppercase mb-1">{item.label}</p>
            <p className={`text-2xl font-black font-mono ${item.color}`}>{item.val.toFixed(3)}<span className="text-xs ml-0.5">"</span></p>
          </div>
        ))}
      </div>

      <div className="bg-white p-6 border border-slate-200 rounded-xl shadow-sm">
        <div className="flex items-center justify-between mb-6 border-b border-slate-100 pb-4">
          <h3 className="text-lg font-bold text-slate-800">角位置偏差分布曲线图 (ISO 230-2)</h3>
          <div className="flex gap-2 no-print">
            <button className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 rounded text-xs font-bold">
              <FileSpreadsheet className="w-4 h-4" /> 导出 CSV
            </button>
            <button onClick={() => window.print()} className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-white rounded text-xs font-bold shadow-md">
              <Printer className="w-4 h-4" /> 打印报告
            </button>
          </div>
        </div>

        <div className="h-[450px] w-full bg-slate-50/50 rounded-lg p-2">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData} margin={{ top: 20, right: 30, left: 10, bottom: 40 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#cbd5e1" vertical={true} />
              <XAxis 
                dataKey="angle" 
                type="number" 
                domain={[0, 360]} 
                ticks={[0, 45, 90, 135, 180, 225, 270, 315, 360]}
                tick={{ fontSize: 11, fill: '#475569', fontWeight: 600 }}
                axisLine={{ stroke: '#1e293b', strokeWidth: 1 }}
              >
                <Label value="目标角度位置 (°)" offset={-20} position="insideBottom" style={{ fontSize: '12px', fontWeight: 700, fill: '#1e293b' }} />
              </XAxis>
              <YAxis 
                domain={yDomain}
                tick={{ fontSize: 11, fill: '#475569', fontWeight: 600 }}
                axisLine={{ stroke: '#1e293b', strokeWidth: 1 }}
              >
                <Label value="偏差值 (arcsec)" angle={-90} position="insideLeft" offset={10} style={{ textAnchor: 'middle', fontSize: '12px', fontWeight: 700, fill: '#1e293b' }} />
              </YAxis>

              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: '1px solid #cbd5e1', fontSize: '11px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)' }}
              />

              <ReferenceLine y={0} stroke="#475569" strokeWidth={1} label={{ position: 'right', value: '0', fontSize: 10, fill: '#64748b' }} />

              {/* 正向线 (均值加粗，单次细线) */}
              {Array.from({ length: numRuns }).map((_, idx) => (
                <Line
                  key={`fRun${idx}`}
                  name={`正向 R${idx + 1}`}
                  dataKey={`fRun${idx}`}
                  stroke={FORWARD_COLOR}
                  strokeWidth={idx === 0 ? 2 : 1}
                  strokeOpacity={idx === 0 ? 1 : 0.4}
                  dot={{ r: 3, fill: FORWARD_COLOR }}
                  type="monotone"
                />
              ))}

              {/* 反向线 (均值加粗，单次细线) */}
              {Array.from({ length: numRuns }).map((_, idx) => (
                <Line
                  key={`rRun${idx}`}
                  name={`反向 R${idx + 1}`}
                  dataKey={`rRun${idx}`}
                  stroke={REVERSE_COLOR}
                  strokeWidth={idx === 0 ? 2 : 1}
                  strokeOpacity={idx === 0 ? 1 : 0.4}
                  dot={{ r: 3, fill: REVERSE_COLOR }}
                  type="monotone"
                />
              ))}
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        {/* 图例说明 */}
        <div className="mt-6 flex items-center justify-center gap-8 text-[11px] font-bold">
          <div className="flex items-center gap-2">
            <div className="w-8 h-0.5 bg-blue-800"></div>
            <span className="text-blue-800">正向轨迹 (Forward)</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-8 h-0.5 bg-red-800"></div>
            <span className="text-red-800">反向轨迹 (Reverse)</span>
          </div>
          <div className="flex items-center gap-2 text-slate-400 font-normal italic">
            <Info className="w-3 h-3" />
            <span>注：加粗线条为首轮测量轨迹，浅色线条为重复性测量。</span>
          </div>
        </div>
      </div>
    </div>
  );
};

