        lowerF: Number((p.meanForward - 2 * p.stdForward).toFixed(3)),
        upperR: Number((p.meanReverse + 2 * p.stdReverse).toFixed(3)),
        lowerR: Number((p.meanReverse - 2 * p.stdReverse).toFixed(3)),
      };
      // Individual runs are kept for reference but can be hidden or made very faint
      p.correctedForwardRuns.forEach((val, idx) => { dataPoint[`fRun${idx}`] = Number(val.toFixed(3)); });
      p.correctedReverseRuns.forEach((val, idx) => { dataPoint[`rRun${idx}`] = Number(val.toFixed(3)); });
      return dataPoint;
    });
  }, [results]);

  const yDomain = useMemo(() => {
    const allVals: number[] = [];
    results.points.forEach(p => {
      allVals.push(
        p.meanForward + 2 * p.stdForward,
        p.meanForward - 2 * p.stdForward,
        p.meanReverse + 2 * p.stdReverse,
        p.meanReverse - 2 * p.stdReverse
      );
    });
    if (allVals.length === 0) return [-5, 5];
    const max = Math.max(...allVals);
    const min = Math.min(...allVals);
    const range = max - min;
    const padding = range === 0 ? 1 : Math.max(range * 0.2, 0.5); 
    return [Math.min(min - padding, -1), Math.max(max + padding, 1)];
  }, [results]);

  return (
    <div className="space-y-6">
      {/* 核心指标看板 */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
