        ].map((item, i) => (
          <div key={i} className={`${item.bg} border border-slate-200 p-4 rounded-lg shadow-sm`}>
            <p className="text-[10px] font-bold text-slate-500 uppercase mb-1">{item.label}</p>
            <p className={`text-2xl font-black font-mono ${item.color}`}>{item.val.toFixed(3)}<span className="text-xs ml-0.5">"</span></p>
          </div>
        ))}
      </div>

      <div className="bg-white p-6 border border-slate-200 rounded-xl shadow-sm">
        <div className="flex items-center justify-between mb-6 border-b border-slate-100 pb-4">
          <h3 className="text-lg font-bold text-slate-800">角位置偏差分布曲线图 (ISO 230-2)</h3>
          <div className="flex gap-2 no-print">
            <button className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 rounded text-xs font-bold">
              <FileSpreadsheet className="w-4 h-4" /> 导出 CSV
            </button>
            <button onClick={() => window.print()} className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-white rounded text-xs font-bold shadow-md">
              <Printer className="w-4 h-4" /> 打印报告
            </button>
          </div>
        </div>

        <div className="h-[550px] w-full bg-slate-50/50 rounded-lg p-2">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData} margin={{ top: 20, right: 30, left: 10, bottom: 40 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#cbd5e1" vertical={true} />
              <XAxis 
                dataKey="angle" 
                type="number" 
                domain={[0, 360]} 
                ticks={[0, 45, 90, 135, 180, 225, 270, 315, 360]}
                tick={{ fontSize: 11, fill: '#475569', fontWeight: 600 }}
                axisLine={{ stroke: '#1e293b', strokeWidth: 1 }}
              >
                <Label value="目标角度位置 (°)" offset={-20} position="insideBottom" style={{ fontSize: '12px', fontWeight: 700, fill: '#1e293b' }} />
              </XAxis>
              <YAxis 
                domain={yDomain}
                tick={{ fontSize: 11, fill: '#475569', fontWeight: 600 }}
                axisLine={{ stroke: '#1e293b', strokeWidth: 1 }}
              >
                <Label value="偏差值 (arcsec)" angle={-90} position="insideLeft" offset={10} style={{ textAnchor: 'middle', fontSize: '12px', fontWeight: 700, fill: '#1e293b' }} />
              </YAxis>

              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: '1px solid #cbd5e1', fontSize: '11px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)' }}
              />

              <ReferenceLine y={0} stroke="#475569" strokeWidth={1} />

              {/* 1. 正向平均偏差 meanF (实线) */}
              <Line
                name="x̄i↑ (正向平均)"
                dataKey="meanF"
                stroke={FORWARD_COLOR}
                strokeWidth={2.5}
                dot={{ r: 4, fill: FORWARD_COLOR }}
                type="monotone"
                zIndex={10}
              />

              {/* 2. 反向平均偏差 meanR (虚线) */}
              <Line
                name="x̄i↓ (反向平均)"
                dataKey="meanR"
                stroke={REVERSE_COLOR}
                strokeWidth={2.5}
                strokeDasharray="8 4"
                dot={{ r: 4, fill: REVERSE_COLOR }}
                type="monotone"
                zIndex={10}
              />

              {/* 3. 正向/反向 离散带 ±2s (点划线) */}
              <Line
                name="x̄i↑ ± 2s↑ (正向离散)"
                dataKey="upperF"
                stroke={FORWARD_COLOR}
                strokeWidth={1}
                strokeDasharray="10 3 2 3"
                dot={false}
                type="monotone"
                strokeOpacity={BAND_OPACITY}
              />
              <Line
                dataKey="lowerF"
                stroke={FORWARD_COLOR}
                strokeWidth={1}
                strokeDasharray="10 3 2 3"
                dot={false}
                type="monotone"
                strokeOpacity={BAND_OPACITY}
              />
              <Line
                name="x̄i↓ ± 2s↓ (反向离散)"
                dataKey="upperR"
                stroke={REVERSE_COLOR}
                strokeWidth={1}
                strokeDasharray="10 3 2 3"
                dot={false}
                type="monotone"
                strokeOpacity={BAND_OPACITY}
              />
              <Line
                dataKey="lowerR"
                stroke={REVERSE_COLOR}
                strokeWidth={1}
                strokeDasharray="10 3 2 3"
                dot={false}
                type="monotone"
                strokeOpacity={BAND_OPACITY}
              />

              {/* 4. 双向平均偏差 meanBi (粗实线) */}
              <Line
                name="x̄i (双向平均)"
                dataKey="meanBi"
                stroke={BI_COLOR}
                strokeWidth={3}
                dot={{ r: 2, fill: BI_COLOR }}
                type="monotone"
              />

              {/* 背景参考细线 (单次循环测量值) - 可选，设为极淡 */}
              {Array.from({ length: numRuns }).map((_, idx) => (
                <Line
                  key={`fRun${idx}`}
                  dataKey={`fRun${idx}`}
                  stroke={FORWARD_COLOR}
