          </div>
          <div className="flex items-center gap-3">
            <div className="w-10 h-1 bg-slate-900"></div>
            <div className="text-xs font-bold text-slate-700">x̄i 双向平均偏差</div>
          </div>
        </div>

        <div className="mt-4 flex items-center gap-2 text-slate-400 text-[11px] font-medium">
          <Info className="w-3 h-3" />
          <span>注：图形显示符合 ISO 230-2:2014 标准定义的计算方法，点划线表示 95% 置信区间带宽。</span>
        </div>
      </div>
    </div>
  );
};

