              <ReferenceLine segment={[{ x: 360, y: isoBounds.A_min }, { x: 375, y: isoBounds.A_min }]} stroke="#94a3b8" />
              <ReferenceLine segment={[{ x: 360, y: isoBounds.A_max }, { x: 375, y: isoBounds.A_max }]} stroke="#94a3b8" />
              <ReferenceArea x1={368} x2={372} y1={isoBounds.A_min} y2={isoBounds.A_max} fill="#1e40af" fillOpacity={0.1}>
