        <div className="mt-4 flex items-center gap-2 text-slate-400 text-[11px] font-medium italic">
          <Info className="w-3 h-3" />
          <span>图表说明：垂直跨度 A, E, M 分别标记了总精度带宽、均值偏差带宽和双向平均带宽；B 标记了最大回程误差。</span>
        </div>
      </div>
    </div>
  );
};

export default ResultDashboard;

import React, { useMemo } from 'react';
import { ISOResult } from '../types';
import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  ReferenceLine, 
  Line,
  ComposedChart,
  Label,
  Legend,
  ReferenceArea
} from 'recharts';
import { Printer, FileSpreadsheet, Info } from 'lucide-react';

interface Props {
  results: ISOResult;
}

const FORWARD_COLOR = '#1e40af'; // 深蓝
const REVERSE_COLOR = '#b91c1c'; // 深红
const BI_COLOR = '#0f172a';      // 深灰/黑
const BAND_OPACITY = 0.5;

const ResultDashboard: React.FC<Props> = ({ results }) => {
  const numRuns = results.points[0]?.correctedForwardRuns.length || 0;

  const chartData = useMemo(() => {
    return results.points.map(p => {
      const dataPoint: any = {
        angle: p.angle,
        meanF: Number(p.meanForward.toFixed(3)),
        meanR: Number(p.meanReverse.toFixed(3)),
        meanBi: Number(((p.meanForward + p.meanReverse) / 2).toFixed(3)),
        upperF: Number((p.meanForward + 2 * p.stdForward).toFixed(3)),
        lowerF: Number((p.meanForward - 2 * p.stdForward).toFixed(3)),
        upperR: Number((p.meanReverse + 2 * p.stdReverse).toFixed(3)),
        lowerR: Number((p.meanReverse - 2 * p.stdReverse).toFixed(3)),
      };
      p.correctedForwardRuns.forEach((val, idx) => { dataPoint[`fRun${idx}`] = Number(val.toFixed(3)); });
      p.correctedReverseRuns.forEach((val, idx) => { dataPoint[`rRun${idx}`] = Number(val.toFixed(3)); });
      return dataPoint;
    });
  }, [results]);

  const isoBounds = useMemo(() => {
    const meanF = results.points.map(p => p.meanForward);
    const meanR = results.points.map(p => p.meanReverse);
    const meanBi = results.points.map(p => (p.meanForward + p.meanReverse) / 2);
    const upperF = results.points.map(p => p.meanForward + 2 * p.stdForward);
    const lowerF = results.points.map(p => p.meanForward - 2 * p.stdForward);
    const upperR = results.points.map(p => p.meanReverse + 2 * p.stdReverse);
    const lowerR = results.points.map(p => p.meanReverse - 2 * p.stdReverse);

    return {
      A_max: Math.max(...upperF, ...upperR),
      A_min: Math.min(...lowerF, ...lowerR),
      E_max: Math.max(...meanF, ...meanR),
      E_min: Math.min(...meanF, ...meanR),
      M_max: Math.max(...meanBi),
      M_min: Math.min(...meanBi),
      maxBPoint: results.points.reduce((prev, curr) => 
        (Math.abs(curr.meanForward - curr.meanReverse) > Math.abs(prev.meanForward - prev.meanReverse) ? curr : prev)
      ),
      maxRPoint: results.points.reduce((prev, curr) => 
        (Math.max(4 * curr.stdForward, 4 * curr.stdReverse) > Math.max(4 * prev.stdForward, 4 * prev.stdReverse) ? curr : prev)
      )
    };
  }, [results]);

  const yDomain = useMemo(() => {
    const min = isoBounds.A_min;
    const max = isoBounds.A_max;
    const range = max - min;
    const padding = range === 0 ? 4 : Math.max(range * 0.4, 2); 
    return [min - padding, max + padding];
  }, [isoBounds]);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4 no-print">
        {[
          { label: '双向定位精度 A', val: results.A, color: 'text-blue-700', bg: 'bg-blue-50' },
          { label: '定位偏差 E', val: results.E, color: 'text-slate-700', bg: 'bg-slate-50' },
          { label: '双向重复精度 R', val: results.R, color: 'text-indigo-700', bg: 'bg-indigo-50' },
          { label: '反向差值 B', val: results.B, color: 'text-red-700', bg: 'bg-red-50' },
          { label: '平均偏差 M', val: results.M, color: 'text-emerald-700', bg: 'bg-emerald-50' },
        ].map((item, i) => (
          <div key={i} className={`${item.bg} border border-slate-200 p-4 rounded-lg shadow-sm`}>
            <p className="text-[10px] font-bold text-slate-500 uppercase mb-1">{item.label}</p>
            <p className={`text-2xl font-black font-mono ${item.color}`}>{item.val.toFixed(3)}<span className="text-xs ml-0.5">"</span></p>
          </div>
        ))}
      </div>

      <div className="bg-white p-6 border border-slate-200 rounded-xl shadow-sm">
        <div className="flex items-center justify-between mb-8 border-b border-slate-100 pb-4 no-print">
          <h3 className="text-lg font-bold text-slate-800 tracking-tight">ISO 230-2 精度评价分布图</h3>
          <div className="flex gap-2">
            <button className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 rounded text-xs font-bold">
              <FileSpreadsheet className="w-4 h-4" /> 导出 CSV
            </button>
            <button onClick={() => window.print()} className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-white rounded text-xs font-bold shadow-md">
              <Printer className="w-4 h-4" /> 打印
            </button>
          </div>
        </div>

        <div className="h-[650px] w-full bg-white p-2">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData} margin={{ top: 20, right: 150, left: 20, bottom: 60 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" vertical={true} />
              <XAxis 
                dataKey="angle" 
                type="number" 
                domain={[0, 360]} 
                ticks={[0, 45, 90, 135, 180, 225, 270, 315, 360]}
                tick={{ fontSize: 11, fill: '#64748b' }}
                axisLine={{ stroke: '#94a3b8' }}
              >
                <Label value="目标角度位置 Target Angle (°)" offset={-40} position="insideBottom" style={{ fontSize: '13px', fontWeight: 600, fill: '#334155' }} />
              </XAxis>
              <YAxis 
                domain={yDomain}
                tick={{ fontSize: 11, fill: '#64748b' }}
                axisLine={{ stroke: '#94a3b8' }}
              >
                <Label value="偏差 Deviation (arcsec)" angle={-90} position="insideLeft" offset={0} style={{ textAnchor: 'middle', fontSize: '13px', fontWeight: 600, fill: '#334155' }} />
              </YAxis>

              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: '1px solid #e2e8f0', fontSize: '11px' }}
              />

              <ReferenceLine y={0} stroke="#94a3b8" strokeWidth={1} />

              {/* ISO 标准标注 - A 双向定位精度 */}
              <ReferenceLine segment={[{ x: 360, y: isoBounds.A_min }, { x: 420, y: isoBounds.A_min }]} stroke="#1e40af" strokeWidth={1} strokeDasharray="4 2" />
              <ReferenceLine segment={[{ x: 360, y: isoBounds.A_max }, { x: 420, y: isoBounds.A_max }]} stroke="#1e40af" strokeWidth={1} strokeDasharray="4 2" />
              <ReferenceArea x1={410} x2={414} y1={isoBounds.A_min} y2={isoBounds.A_max} fill="#1e40af" fillOpacity={0.2}>
                <Label value={`A = ${results.A.toFixed(3)}"`} position="right" offset={10} style={{ fontSize: '12px', fontWeight: 'bold', fill: '#1e40af' }} />
              </ReferenceArea>

              {/* ISO 标准标注 - E 定位偏差 */}
              <ReferenceLine segment={[{ x: 360, y: isoBounds.E_min }, { x: 395, y: isoBounds.E_min }]} stroke="#475569" strokeWidth={1} strokeDasharray="4 2" />
              <ReferenceLine segment={[{ x: 360, y: isoBounds.E_max }, { x: 395, y: isoBounds.E_max }]} stroke="#475569" strokeWidth={1} strokeDasharray="4 2" />
              <ReferenceArea x1={385} x2={388} y1={isoBounds.E_min} y2={isoBounds.E_max} fill="#475569" fillOpacity={0.2}>
                <Label value={`E = ${results.E.toFixed(3)}"`} position="right" offset={10} style={{ fontSize: '11px', fontWeight: 'bold', fill: '#475569' }} />
              </ReferenceArea>

              {/* ISO 标准标注 - M 平均双向偏差 */}
              <ReferenceLine segment={[{ x: 360, y: isoBounds.M_min }, { x: 375, y: isoBounds.M_min }]} stroke="#0f172a" strokeWidth={1} strokeDasharray="4 2" />
              <ReferenceLine segment={[{ x: 360, y: isoBounds.M_max }, { x: 375, y: isoBounds.M_max }]} stroke="#0f172a" strokeWidth={1} strokeDasharray="4 2" />
              <ReferenceArea x1={368} x2={371} y1={isoBounds.M_min} y2={isoBounds.M_max} fill="#0f172a" fillOpacity={0.2}>
                <Label value={`M = ${results.M.toFixed(3)}"`} position="right" offset={10} style={{ fontSize: '11px', fontWeight: 'bold', fill: '#0f172a' }} />
              </ReferenceArea>

              {/* ISO 标准标注 - B 最大反向差值 */}
              <ReferenceLine 
                segment={[
                  { x: isoBounds.maxBPoint.angle, y: isoBounds.maxBPoint.meanForward }, 
                  { x: isoBounds.maxBPoint.angle, y: isoBounds.maxBPoint.meanReverse }
                ]} 
                stroke="#b91c1c" strokeWidth={2}
              >
                <Label value={`B = ${results.B.toFixed(3)}"`} position="top" offset={15} style={{ fontSize: '11px', fontWeight: 'bold', fill: '#b91c1c' }} />
              </ReferenceLine>

              {/* ISO 标准标注 - R 最大重复精度 */}
              <ReferenceLine 
                segment={[
                  { x: isoBounds.maxRPoint.angle, y: isoBounds.maxRPoint.meanForward - 2 * isoBounds.maxRPoint.stdForward }, 
                  { x: isoBounds.maxRPoint.angle, y: isoBounds.maxRPoint.meanForward + 2 * isoBounds.maxRPoint.stdForward }
                ]} 
                stroke="#4338ca" strokeWidth={1.5}
              >
                <Label value={`R = ${results.R.toFixed(3)}"`} position="bottom" offset={15} style={{ fontSize: '11px', fontWeight: 'bold', fill: '#4338ca' }} />
              </ReferenceLine>

              {/* 1. 正向平均偏差 x̄i↑ (实线) */}
              <Line
                name="x̄i↑ (正向平均)"
                dataKey="meanF"
                stroke={FORWARD_COLOR}
                strokeWidth={2.5}
                dot={{ r: 4, fill: FORWARD_COLOR, strokeWidth: 0 }}
                type="monotone"
                zIndex={20}
              />

              {/* 2. 反向平均偏差 x̄i↓ (虚线) */}
              <Line
                name="x̄i↓ (反向平均)"
                dataKey="meanR"
                stroke={REVERSE_COLOR}
                strokeWidth={2.5}
                strokeDasharray="8 4"
                dot={{ r: 4, fill: REVERSE_COLOR, strokeWidth: 0 }}
                type="monotone"
                zIndex={20}
              />

              {/* 3. 正向/反向 离散带 ±2s (点划线) */}
              <Line
                name="x̄i↑ ± 2s↑"
                dataKey="upperF"
                stroke={FORWARD_COLOR}
                strokeWidth={1}
                strokeDasharray="10 3 2 3"
                dot={false}
                type="monotone"
                strokeOpacity={BAND_OPACITY}
              />
              <Line
                dataKey="lowerF"
                stroke={FORWARD_COLOR}
                strokeWidth={1}
                strokeDasharray="10 3 2 3"
                dot={false}
                type="monotone"
                strokeOpacity={BAND_OPACITY}
              />
              <Line
                name="x̄i↓ ± 2s↓"
                dataKey="upperR"
                stroke={REVERSE_COLOR}
                strokeWidth={1}
                strokeDasharray="10 3 2 3"
                dot={false}
                type="monotone"
                strokeOpacity={BAND_OPACITY}
              />
              <Line
                dataKey="lowerR"
                stroke={REVERSE_COLOR}
                strokeWidth={1}
                strokeDasharray="10 3 2 3"
                dot={false}
                type="monotone"
                strokeOpacity={BAND_OPACITY}
              />

              {/* 4. 双向平均偏差 x̄i (粗实线) */}
              <Line
                name="x̄i (双向平均)"
                dataKey="meanBi"
                stroke={BI_COLOR}
                strokeWidth={3}
                dot={{ r: 2, fill: BI_COLOR }}
                type="monotone"
                zIndex={25}
              />

              <Legend verticalAlign="bottom" align="center" height={36} wrapperStyle={{ paddingTop: '20px' }} />
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        <div className="mt-4 grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-6 p-6 bg-slate-50 border border-slate-200 rounded-lg">
          <div className="space-y-1">
            <div className="flex items-center gap-2">
              <div className="w-8 h-1 bg-blue-800"></div>
              <span className="text-xs font-bold text-slate-800">A</span>
            </div>
            <p className="text-[10px] text-slate-500 font-medium">双向定位精度 (Accuracy)</p>
          </div>
          <div className="space-y-1">
            <div className="flex items-center gap-2">
              <div className="w-8 h-1 bg-slate-500"></div>
              <span className="text-xs font-bold text-slate-800">E</span>
            </div>
            <p className="text-[10px] text-slate-500 font-medium">定位偏差 (Error Range)</p>
          </div>
          <div className="space-y-1">
            <div className="flex items-center gap-2">
              <div className="w-8 h-1 bg-slate-900"></div>
              <span className="text-xs font-bold text-slate-800">M</span>
            </div>
            <p className="text-[10px] text-slate-500 font-medium">平均偏差 (Mean Range)</p>
          </div>
          <div className="space-y-1">
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 border-l-2 border-red-700"></div>
              <span className="text-xs font-bold text-slate-800">B</span>
            </div>
            <p className="text-[10px] text-slate-500 font-medium">反向差值 (Reversal)</p>
          </div>
          <div className="space-y-1">
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 border-l-2 border-indigo-700 border-dotted"></div>
              <span className="text-xs font-bold text-slate-800">R</span>
            </div>
            <p className="text-[10px] text-slate-500 font-medium">重复精度 (Repeatability)</p>
          </div>
        </div>
      </div>
    </div>
  );
};

