import { MeasurementPoint, PrismFaceData, ISOResult, CalculatedPoint } from '../types';

export const calculateISO230 = (
  measurements: MeasurementPoint[],
  prismData: PrismFaceData[]
): ISOResult => {
  // 核心：寻找全局零点 (第一个测回的正向 0° 读数)
  // 我们假设 measurements[0] 是 0° 位置
  const globalZeroOffset = measurements[0]?.forwardReadings[0] || 0;

  const points: CalculatedPoint[] = measurements.map((m, i) => {
    const prismError = prismData[i]?.error || 0;

    // 修正公式: (原始读数 - 全局零点) + 棱体偏差
    // 注意：棱体偏差是证书给出的差值，需要加回到相对读数上
    const correctedF = m.forwardReadings.map(v => (v - globalZeroOffset) + prismError);
    const correctedR = m.reverseReadings.map(v => (v - globalZeroOffset) + prismError);

    const n = correctedF.length;
    const meanF = correctedF.reduce((a, b) => a + b, 0) / n;
    const meanR = correctedR.reduce((a, b) => a + b, 0) / n;

    const stdF = n > 1 
      ? Math.sqrt(correctedF.reduce((sq, val) => sq + Math.pow(val - meanF, 2), 0) / (n - 1)) 
      : 0;
    const stdR = n > 1 
      ? Math.sqrt(correctedR.reduce((sq, val) => sq + Math.pow(val - meanR, 2), 0) / (n - 1)) 
      : 0;

    return {
      angle: m.targetAngle,
      prismError,
      correctedForwardRuns: correctedF,
      correctedReverseRuns: correctedR,
      meanForward: meanF,
      meanReverse: meanR,
      stdForward: stdF,
      stdReverse: stdR,
      deviationForward: meanF,
      deviationReverse: meanR,
      reversalError: Math.abs(meanF - meanR)
    };
  });

  const upperBandsF = points.map(p => p.meanForward + 2 * p.stdForward);
  const lowerBandsF = points.map(p => p.meanForward - 2 * p.stdForward);
  const upperBandsR = points.map(p => p.meanReverse + 2 * p.stdReverse);
  const lowerBandsR = points.map(p => p.meanReverse - 2 * p.stdReverse);

  // ISO 230-2 指标计算
  const A = Math.max(...upperBandsF, ...upperBandsR) - Math.min(...lowerBandsF, ...lowerBandsR);
  const E = Math.max(...points.map(p => p.meanForward), ...points.map(p => p.meanReverse)) - 
            Math.min(...points.map(p => p.meanForward), ...points.map(p => p.meanReverse));

  const R_up = Math.max(...points.map(p => 4 * p.stdForward));
  const R_down = Math.max(...points.map(p => 4 * p.stdReverse));
  const R = Math.max(R_up, R_down);

  const B = Math.max(...points.map(p => p.reversalError));

  const biMeans = points.map(p => (p.meanForward + p.meanReverse) / 2);
  const M = Math.max(...biMeans) - Math.min(...biMeans);

  return {
    A,
    A_up: Math.max(...upperBandsF) - Math.min(...lowerBandsF),
    A_down: Math.max(...upperBandsR) - Math.min(...lowerBandsR),
    R,
    R_up,
    R_down,
    B,
    E,
    E_up: Math.max(...points.map(p => p.meanForward)) - Math.min(...points.map(p => p.meanForward)),
    E_down: Math.max(...points.map(p => p.meanReverse)) - Math.min(...points.map(p => p.meanReverse)),
    M,
    points
  };
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { PrismFaceData, MeasurementPoint, ISOResult } from './types';
import PrismTable from './components/PrismTable';
import MeasurementTable from './components/MeasurementTable';
import ResultDashboard from './components/ResultDashboard';
import { calculateISO230 } from './services/isoCalculator';
import { analyzeTestResults } from './services/geminiService';
import { 
  ClipboardCheck, BarChart3, ChevronRight, Activity, 
  Cpu, FileText, Layers, Database, X, Upload, CheckCircle2,
  AlertCircle
} from 'lucide-react';

const NUM_FACES = 24;
const INITIAL_PRISM_DATA: PrismFaceData[] = Array.from({ length: NUM_FACES }, (_, i) => ({
  face: i + 1,
  targetAngle: i * 15,
  error: 0
}));

const INITIAL_MEASUREMENTS: (numRuns: number) => MeasurementPoint[] = (numRuns) => 
  Array.from({ length: NUM_FACES }, (_, i) => ({
    face: i + 1,
    targetAngle: i * 15,
    forwardReadings: Array(numRuns).fill(0),
    reverseReadings: Array(numRuns).fill(0)
  }));

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'config' | 'measure' | 'results'>('config');
  const [numRuns, setNumRuns] = useState(5);
  const [prismData, setPrismData] = useState<PrismFaceData[]>(INITIAL_PRISM_DATA);
  const [measurements, setMeasurements] = useState<MeasurementPoint[]>(INITIAL_MEASUREMENTS(5));
  const [aiReport, setAiReport] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // 导入对话框状态
  const [importType, setImportType] = useState<'prism' | 'reading' | null>(null);
  const [importText, setImportText] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setMeasurements(prev => prev.map(m => ({
      ...m,
      forwardReadings: m.forwardReadings.length === numRuns ? [...m.forwardReadings] : Array(numRuns).fill(0),
      reverseReadings: m.reverseReadings.length === numRuns ? [...m.reverseReadings] : Array(numRuns).fill(0)
    })));
  }, [numRuns]);

  const results = useMemo(() => calculateISO230(measurements, prismData), [measurements, prismData]);

  // 核心：处理准直仪 0-345-0 序列导入
  const processReadingImport = (text: string) => {
    const allNumbers = text.match(/-?\d+(\.\d+)?/g)?.map(Number) || [];
    if (allNumbers.length === 0) {
      alert("未能在输入中找到有效数值。");
      return;
    }

    setMeasurements(prev => {
      const next = [...prev];
      let pointer = 0;
      let runsProcessed = 0;

      // 准直仪通常一测回 48 个点 (24 正 + 24 反)
      while (pointer < allNumbers.length && runsProcessed < numRuns) {
        // 处理正向序列 (0 -> 345)
        for (let i = 0; i < NUM_FACES; i++) {
          if (pointer < allNumbers.length) {
            next[i].forwardReadings[runsProcessed] = allNumbers[pointer++];
          }
        }
        // 处理反向序列 (345 -> 0)
        for (let i = NUM_FACES - 1; i >= 0; i--) {
          if (pointer < allNumbers.length) {
            next[i].reverseReadings[runsProcessed] = allNumbers[pointer++];
          }
        }
        runsProcessed++;
      }
      return next;
    });

    alert(`成功按 0-345-0 序列导入了 ${Math.min(Math.ceil(allNumbers.length / 48), numRuns)} 个测回的数据！`);
    setImportType(null);
    setImportText('');
  };

  const processPrismImport = (text: string) => {
    const lines = text.trim().split(/\r?\n/);
    let count = 0;
    setPrismData(prev => {
      const next = [...prev];
      lines.forEach((line, i) => {
        const nums = line.match(/-?\d+(\.\d+)?/g);
        if (nums && nums.length > 0 && i < next.length) {
          next[i] = { ...next[i], error: parseFloat(nums[nums.length - 1]) };
          count++;
        }
      });
      return next;
    });
    alert(`已导入 ${count} 条棱体偏差修正值。`);
    setImportType(null);
    setImportText('');
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      if (importType === 'prism') processPrismImport(content);
      else if (importType === 'reading') processReadingImport(content);
    };
    reader.readAsText(file);
  };

  const handleMeasurementChange = (faceIdx: number, type: 'forward' | 'reverse', runIdx: number, value: number) => {
    setMeasurements(prev => prev.map((m, idx) => {
      if (idx === faceIdx) {
        const newM = { ...m };
        if (type === 'forward') {
          const newF = [...m.forwardReadings];
          newF[runIdx] = value;
          newM.forwardReadings = newF;
        } else {
          const newR = [...m.reverseReadings];
          newR[runIdx] = value;
          newM.reverseReadings = newR;
        }
        return newM;
      }
      return m;
    }));
  };

  const loadDemoData = () => {
    const demoPrism = prismData.map((d, i) => ({ ...d, error: Number((Math.sin(i * 0.5) * 0.5).toFixed(2)) }));
    const demoMeas = measurements.map((m, i) => ({
      ...m,
      forwardReadings: m.forwardReadings.map(() => Number((10 + Math.sin(i * 0.4) * 5 + Math.random() * 0.5).toFixed(2))),
      reverseReadings: m.reverseReadings.map(() => Number((11 + Math.sin(i * 0.4) * 5 + Math.random() * 0.5).toFixed(2)))
    }));
    setPrismData(demoPrism);
    setMeasurements(demoMeas);
    setActiveTab('results');
  };

  const handleGenerateReport = async () => {
    setIsAnalyzing(true);
    setAiReport(null);
    try {
      const report = await analyzeTestResults(results);
      setAiReport(report);
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
