import { GoogleGenAI } from "@google/genai";
import { ISOResult } from "../types";

export const analyzeTestResults = async (results: ISOResult): Promise<string> => {
  // Use gemini-3-pro-preview for complex metrology reasoning and STEM tasks
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    作为计量院资深工程师，请分析以下直驱转台的测试数据（ISO 230-2标准）：

    测试结果：
    - 双向定位精度 (A): ${results.A.toFixed(2)} "
    - 重复定位精度 (R): ${results.R.toFixed(2)} "
    - 反向差值 (B): ${results.B.toFixed(2)} "
    - 定位偏差 (E): ${results.E.toFixed(2)} "

    数据详情：
    ${results.points.map(p => `角度 ${p.angle}°: 正向偏差 ${p.meanForward.toFixed(2)}", 反向偏差 ${p.meanReverse.toFixed(2)}"`).join('\n')}

    请提供：
    1. 精度评价（是否合格，通常直驱转台精度在1-5秒以内）。
    2. 误差原因分析（如：周期性误差可能源于编码器安装偏心、反向误差大可能源于控制算法或轴承预紧）。
    3. 维护建议。
    4. 简短总结。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
    });
    // Property access .text is correct for GenerateContentResponse
    return response.text || "未能生成分析报告。";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "AI 分析服务暂不可用。";
  }
};

import React, { useMemo } from 'react';
import { ISOResult } from '../types';
import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  ReferenceLine, 
  Line,
  ComposedChart,
  Label,
  Legend,
  ReferenceArea
} from 'recharts';
import { Printer, FileSpreadsheet } from 'lucide-react';

interface Props {
  results: ISOResult;
}

const FORWARD_COLOR = '#1e40af'; // 深蓝
const REVERSE_COLOR = '#b91c1c'; // 深红
const BI_COLOR = '#0f172a';      // 深灰/黑
const BAND_OPACITY = 0.5;

const ResultDashboard: React.FC<Props> = ({ results }) => {
  const chartData = useMemo(() => {
    return results.points.map(p => {
      const dataPoint: any = {
        angle: p.angle,
        meanF: Number(p.meanForward.toFixed(3)),
        meanR: Number(p.meanReverse.toFixed(3)),
        meanBi: Number(((p.meanForward + p.meanReverse) / 2).toFixed(3)),
        upperF: Number((p.meanForward + 2 * p.stdForward).toFixed(3)),
        lowerF: Number((p.meanForward - 2 * p.stdForward).toFixed(3)),
        upperR: Number((p.meanReverse + 2 * p.stdReverse).toFixed(3)),
        lowerR: Number((p.meanReverse - 2 * p.stdReverse).toFixed(3)),
      };
      p.correctedForwardRuns.forEach((val, idx) => { dataPoint[`fRun${idx}`] = Number(val.toFixed(3)); });
      p.correctedReverseRuns.forEach((val, idx) => { dataPoint[`rRun${idx}`] = Number(val.toFixed(3)); });
      return dataPoint;
    });
  }, [results]);

  const isoBounds = useMemo(() => {
    const meanF = results.points.map(p => p.meanForward);
    const meanR = results.points.map(p => p.meanReverse);
    const meanBi = results.points.map(p => (p.meanForward + p.meanReverse) / 2);
    const upperF = results.points.map(p => p.meanForward + 2 * p.stdForward);
    const lowerF = results.points.map(p => p.meanForward - 2 * p.stdForward);
    const upperR = results.points.map(p => p.meanReverse + 2 * p.stdReverse);
    const lowerR = results.points.map(p => p.meanReverse - 2 * p.stdReverse);

    return {
      A_max: Math.max(...upperF, ...upperR),
      A_min: Math.min(...lowerF, ...lowerR),
      E_max: Math.max(...meanF, ...meanR),
      E_min: Math.min(...meanF, ...meanR),
      M_max: Math.max(...meanBi),
      M_min: Math.min(...meanBi),
      maxBPoint: results.points.reduce((prev, curr) => 
        (Math.abs(curr.meanForward - curr.meanReverse) > Math.abs(prev.meanForward - prev.meanReverse) ? curr : prev)
      ),
      maxRPoint: results.points.reduce((prev, curr) => 
        (Math.max(4 * curr.stdForward, 4 * curr.stdReverse) > Math.max(4 * prev.stdForward, 4 * prev.stdReverse) ? curr : prev)
      )
    };
  }, [results]);

  // 优化纵坐标 Domain 算法
  const yDomain = useMemo(() => {
    const min = isoBounds.A_min;
    const max = isoBounds.A_max;
    const range = max - min;
    // 减小 Padding 比例，让曲线更饱满
    const padding = range === 0 ? 2 : Math.max(range * 0.15, 1); 
    return [Math.floor(min - padding), Math.ceil(max + padding)];
  }, [isoBounds]);

  return (
    <div className="space-y-6">
      {/* 核心指标看板 */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4 no-print">
        {[
          { label: '双向定位精度 A', val: results.A, color: 'text-blue-700', bg: 'bg-blue-50' },
          { label: '定位偏差 E', val: results.E, color: 'text-slate-700', bg: 'bg-slate-50' },
          { label: '双向重复精度 R', val: results.R, color: 'text-indigo-700', bg: 'bg-indigo-50' },
          { label: '反向差值 B', val: results.B, color: 'text-red-700', bg: 'bg-red-50' },
          { label: '平均偏差 M', val: results.M, color: 'text-emerald-700', bg: 'bg-emerald-50' },
        ].map((item, i) => (
          <div key={i} className={`${item.bg} border border-slate-200 p-4 rounded-lg shadow-sm`}>
            <p className="text-[10px] font-bold text-slate-500 uppercase mb-1">{item.label}</p>
            <p className={`text-2xl font-black font-mono ${item.color}`}>{item.val.toFixed(3)}<span className="text-xs ml-0.5">"</span></p>
          </div>
        ))}
      </div>

      <div className="bg-white p-6 border border-slate-200 rounded-xl shadow-sm overflow-hidden">
        <div className="flex items-center justify-between mb-8 border-b border-slate-100 pb-4 no-print">
          <h3 className="text-lg font-bold text-slate-800">ISO 230-2 精度特性分布图</h3>
          <div className="flex gap-2">
            <button className="flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 rounded text-xs font-bold">
              <FileSpreadsheet className="w-4 h-4" /> 导出 CSV
            </button>
            <button onClick={() => window.print()} className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-white rounded text-xs font-bold shadow-md">
              <Printer className="w-4 h-4" /> 打印报告
            </button>
          </div>
        </div>

        <div className="h-[600px] w-full bg-white relative">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData} margin={{ top: 20, right: 140, left: 20, bottom: 40 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" vertical={true} />

              <XAxis 
                dataKey="angle" 
                type="number" 
                domain={[0, 360]} 
                ticks={[0, 45, 90, 135, 180, 225, 270, 315, 360]}
                tick={{ fontSize: 11, fill: '#64748b' }}
                axisLine={{ stroke: '#94a3b8' }}
              >
                {/* 调整横坐标标题偏移，避开下方图例 */}
                <Label 
                  value="目标角度位置 (Target Angle / °)" 
                  offset={-25} 
                  position="insideBottom" 
                  style={{ fontSize: '12px', fontWeight: 600, fill: '#475569' }} 
                />
              </XAxis>

              <YAxis 
                domain={yDomain}
                tick={{ fontSize: 11, fill: '#64748b' }}
                axisLine={{ stroke: '#94a3b8' }}
                width={50}
              >
                <Label 
                  value="偏差角秒 (Deviation / arcsec)" 
                  angle={-90} 
                  position="insideLeft" 
                  offset={0} 
                  style={{ textAnchor: 'middle', fontSize: '12px', fontWeight: 600, fill: '#475569' }} 
                />
              </YAxis>

              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: '1px solid #e2e8f0', fontSize: '11px', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
              />

              <ReferenceLine y={0} stroke="#94a3b8" strokeWidth={1} />

              {/* ISO 230-2 指标标注逻辑保持，但优化了线条位置 */}
              <ReferenceLine segment={[{ x: 360, y: isoBounds.A_min }, { x: 460, y: isoBounds.A_min }]} stroke="#1e40af" strokeWidth={1} strokeDasharray="4 4" />
              <ReferenceLine segment={[{ x: 360, y: isoBounds.A_max }, { x: 460, y: isoBounds.A_max }]} stroke="#1e40af" strokeWidth={1} strokeDasharray="4 4" />
              <ReferenceArea x1={420} x2={425} y1={isoBounds.A_min} y2={isoBounds.A_max} fill="#1e40af" fillOpacity={0.15}>
                <Label value={`A = ${results.A.toFixed(3)}"`} position="right" offset={10} style={{ fontSize: '12px', fontWeight: 'bold', fill: '#1e40af' }} />
              </ReferenceArea>

              <ReferenceLine segment={[{ x: 360, y: isoBounds.E_min }, { x: 400, y: isoBounds.E_min }]} stroke="#475569" strokeWidth={1} strokeDasharray="3 3" />
              <ReferenceLine segment={[{ x: 360, y: isoBounds.E_max }, { x: 400, y: isoBounds.E_max }]} stroke="#475569" strokeWidth={1} strokeDasharray="3 3" />
              <ReferenceArea x1={385} x2={388} y1={isoBounds.E_min} y2={isoBounds.E_max} fill="#475569" fillOpacity={0.15}>
                <Label value={`E = ${results.E.toFixed(3)}"`} position="right" offset={8} style={{ fontSize: '11px', fontWeight: 'bold', fill: '#475569' }} />
              </ReferenceArea>

              {/* 曲线绘制 */}
              <Line name="x̄i↑ (正向平均)" dataKey="meanF" stroke={FORWARD_COLOR} strokeWidth={2} dot={{ r: 3.5, fill: FORWARD_COLOR, strokeWidth: 0 }} type="monotone" />
              <Line name="x̄i↓ (反向平均)" dataKey="meanR" stroke={REVERSE_COLOR} strokeWidth={2} strokeDasharray="6 3" dot={{ r: 3.5, fill: REVERSE_COLOR, strokeWidth: 0 }} type="monotone" />
              <Line name="x̄i↑ ± 2s↑" dataKey="upperF" stroke={FORWARD_COLOR} strokeWidth={0.8} strokeDasharray="8 4" dot={false} type="monotone" strokeOpacity={BAND_OPACITY} />
              <Line dataKey="lowerF" stroke={FORWARD_COLOR} strokeWidth={0.8} strokeDasharray="8 4" dot={false} type="monotone" strokeOpacity={BAND_OPACITY} />
              <Line name="x̄i↓ ± 2s↓" dataKey="upperR" stroke={REVERSE_COLOR} strokeWidth={0.8} strokeDasharray="8 4" dot={false} type="monotone" strokeOpacity={BAND_OPACITY} />
              <Line dataKey="lowerR" stroke={REVERSE_COLOR} strokeWidth={0.8} strokeDasharray="8 4" dot={false} type="monotone" strokeOpacity={BAND_OPACITY} />
              <Line name="x̄i (双向平均)" dataKey="meanBi" stroke={BI_COLOR} strokeWidth={2.5} dot={{ r: 2, fill: BI_COLOR }} type="monotone" />

              <Legend verticalAlign="bottom" align="center" height={30} wrapperStyle={{ paddingTop: '10px' }} />
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        {/* 底部详细图例面板 */}
        <div className="mt-4 grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4 p-4 bg-slate-50 border border-slate-100 rounded-lg">
          <div className="space-y-0.5">
            <div className="flex items-center gap-2"><div className="w-6 h-0.5 bg-blue-800"></div><span className="text-[11px] font-bold text-slate-800">A (Accuracy)</span></div>
            <p className="text-[10px] text-slate-500">双向定位精度 (角秒)</p>
          </div>
          <div className="space-y-0.5">
            <div className="flex items-center gap-2"><div className="w-6 h-0.5 bg-slate-500"></div><span className="text-[11px] font-bold text-slate-800">E (Range)</span></div>
            <p className="text-[10px] text-slate-500">定位偏差范围 (角秒)</p>
          </div>
          <div className="space-y-0.5">
            <div className="flex items-center gap-2"><div className="w-6 h-0.5 bg-slate-900"></div><span className="text-[11px] font-bold text-slate-800">M (Mean)</span></div>
            <p className="text-[10px] text-slate-500">平均双向偏差 (角秒)</p>
          </div>
          <div className="space-y-0.5">
            <div className="flex items-center gap-2"><div className="w-3 h-3 border-l-2 border-red-700"></div><span className="text-[11px] font-bold text-slate-800">B (Reversal)</span></div>
            <p className="text-[10px] text-slate-500">反向差值 (回程误差)</p>
          </div>
          <div className="space-y-0.5">
            <div className="flex items-center gap-2"><div className="w-3 h-3 border-l-2 border-indigo-700 border-dotted"></div><span className="text-[11px] font-bold text-slate-800">R (Repeat)</span></div>
            <p className="text-[10px] text-slate-500">双向重复精度 (角秒)</p>
          </div>
        </div>
      </div>
    </div>
  );
};

