              <Printer className="w-4 h-4" /> 打印报告
            </button>
          </div>
        </div>

        <div className="h-[600px] w-full bg-white relative">
          <ResponsiveContainer width="100%" height="100%">
            {/* 调整 margin 进一步压缩空间 */}
            <ComposedChart data={chartData} margin={{ top: 10, right: 140, left: 10, bottom: 10 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" vertical={true} />

              <XAxis 
                dataKey="angle" 
                type="number" 
                domain={[0, 360]} 
                ticks={[0, 45, 90, 135, 180, 225, 270, 315, 360]}
                tick={{ fontSize: 11, fill: '#64748b' }}
                axisLine={{ stroke: '#94a3b8' }}
              />

              <YAxis 
                domain={yDomain}
                tick={{ fontSize: 11, fill: '#64748b' }}
                axisLine={{ stroke: '#94a3b8' }}
                width={40}
                allowDecimals={true}
              />

              <Tooltip 
