              <ReferenceLine segment={[{ x: 360, y: isoBounds.E_min }, { x: 400, y: isoBounds.E_min }]} stroke="#475569" strokeWidth={1} strokeDasharray="3 3" />
              <ReferenceLine segment={[{ x: 360, y: isoBounds.E_max }, { x: 400, y: isoBounds.E_max }]} stroke="#475569" strokeWidth={1} strokeDasharray="3 3" />
