import React, { useMemo } from 'react';
import { ISOResult } from '../types';
import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  ReferenceLine, 
  Line,
  ComposedChart,
  Label,
  Legend,
  ReferenceArea
} from 'recharts';
import { Printer, FileSpreadsheet } from 'lucide-react';

interface Props {
  results: ISOResult;
}

const FORWARD_COLOR = '#1e40af'; // 深蓝
const REVERSE_COLOR = '#b91c1c'; // 深红
const BI_COLOR = '#0f172a';      // 深灰/黑
const BAND_OPACITY = 0.5;

const ResultDashboard: React.FC<Props> = ({ results }) => {
  const chartData = useMemo(() => {
    return results.points.map(p => {
      const dataPoint: any = {
        angle: p.angle,
        meanF: Number(p.meanForward.toFixed(3)),
        meanR: Number(p.meanReverse.toFixed(3)),
        meanBi: Number(((p.meanForward + p.meanReverse) / 2).toFixed(3)),
        upperF: Number((p.meanForward + 2 * p.stdForward).toFixed(3)),
        lowerF: Number((p.meanForward - 2 * p.stdForward).toFixed(3)),
        upperR: Number((p.meanReverse + 2 * p.stdReverse).toFixed(3)),
        lowerR: Number((p.meanReverse - 2 * p.stdReverse).toFixed(3)),
      };
      return dataPoint;
    });
  }, [results]);

  const isoBounds = useMemo(() => {
    // 获取所有曲线的全局极值，用于确定坐标系量程
    const allValues = results.points.flatMap(p => [
      p.meanForward + 2 * p.stdForward,
      p.meanForward - 2 * p.stdForward,
      p.meanReverse + 2 * p.stdReverse,
      p.meanReverse - 2 * p.stdReverse
    ]);

    return {
      min: Math.min(...allValues),
      max: Math.max(...allValues),
      A_max: Math.max(...results.points.map(p => Math.max(p.meanForward + 2 * p.stdForward, p.meanReverse + 2 * p.stdReverse))),
      A_min: Math.min(...results.points.map(p => Math.min(p.meanForward - 2 * p.stdForward, p.meanReverse - 2 * p.stdReverse))),
      E_max: Math.max(...results.points.map(p => Math.max(p.meanForward, p.meanReverse))),
      E_min: Math.min(...results.points.map(p => Math.min(p.meanForward, p.meanReverse))),
    };
  }, [results]);

  // 动态量程算法：根据峰峰值自动适配
  const yDomain = useMemo(() => {
    const range = isoBounds.max - isoBounds.min;
    // 如果没有波动，给 2 秒的显示宽度
    if (range === 0) return [isoBounds.min - 1, isoBounds.max + 1];

    // 设置 10% 的上下缓冲，确保曲线饱满且不触顶
    const padding = range * 0.1;
    return [
      Number((isoBounds.min - padding).toFixed(2)),
      Number((isoBounds.max + padding).toFixed(2))
    ];
  }, [isoBounds]);

  return (
    <div className="space-y-6">
      {/* 核心指标看板 */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4 no-print">
        {[
          { label: '双向定位精度 A', val: results.A, color: 'text-blue-700', bg: 'bg-blue-50' },
          { label: '定位偏差 E', val: results.E, color: 'text-slate-700', bg: 'bg-slate-50' },
          { label: '双向重复精度 R', val: results.R, color: 'text-indigo-700', bg: 'bg-indigo-50' },
          { label: '反向差值 B', val: results.B, color: 'text-red-700', bg: 'bg-red-50' },
          { label: '平均偏差 M', val: results.M, color: 'text-emerald-700', bg: 'bg-emerald-50' },
        ].map((item, i) => (
          <div key={i} className={`${item.bg} border border-slate-200 p-4 rounded-lg shadow-sm`}>
            <p className="text-[10px] font-bold text-slate-500 uppercase mb-1">{item.label}</p>
            <p className={`text-2xl font-black font-mono ${item.color}`}>{item.val.toFixed(3)}<span className="text-xs ml-0.5">"</span></p>
          </div>
        ))}
      </div>

      <div className="bg-white p-6 border border-slate-200 rounded-xl shadow-sm overflow-hidden">
        <div className="flex items-center justify-between mb-6 border-b border-slate-100 pb-4 no-print">
          <h3 className="text-lg font-bold text-slate-800">ISO 230-2 精度特性分布图</h3>
          <div className="flex gap-2">
            <button className="px-3 py-1.5 bg-white border border-slate-200 hover:bg-slate-50 text-slate-600 rounded text-xs font-bold flex items-center gap-2">
              <FileSpreadsheet className="w-4 h-4" /> 导出 CSV
            </button>
            <button onClick={() => window.print()} className="px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-white rounded text-xs font-bold shadow-md flex items-center gap-2">
              <Printer className="w-4 h-4" /> 打印报告
            </button>
          </div>
        </div>

        <div className="h-[550px] w-full bg-white relative">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={chartData} margin={{ top: 20, right: 20, left: 30, bottom: 20 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" vertical={true} />

              <XAxis 
                dataKey="angle" 
                type="number" 
                domain={[0, 360]} 
                ticks={[0, 45, 90, 135, 180, 225, 270, 315, 360]}
                tick={{ fontSize: 11, fill: '#64748b' }}
                axisLine={{ stroke: '#e2e8f0' }}
              />

              <YAxis 
                domain={yDomain}
                tick={{ fontSize: 11, fill: '#64748b' }}
                axisLine={{ stroke: '#e2e8f0' }}
                allowDecimals={true}
              >
                {/* 恢复纵坐标标题 */}
                <Label 
                  value="偏差 (arcsec)" 
                  angle={-90} 
                  position="insideLeft" 
                  offset={-15}
                  style={{ textAnchor: 'middle', fontSize: '12px', fontWeight: 600, fill: '#475569' }} 
                />
              </YAxis>

              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: 'none', fontSize: '11px', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                formatter={(value: number) => [`${value.toFixed(3)} "`, ""]}
              />

              <ReferenceLine y={0} stroke="#94a3b8" strokeWidth={1} />

              {/* 关键修正：确保标注线在 X 轴有效范围内，且不拉伸坐标系 */}
              <ReferenceLine segment={[{ x: 345, y: isoBounds.A_min }, { x: 360, y: isoBounds.A_min }]} stroke="#1e40af" strokeWidth={1} strokeDasharray="3 3" />
              <ReferenceLine segment={[{ x: 345, y: isoBounds.A_max }, { x: 360, y: isoBounds.A_max }]} stroke="#1e40af" strokeWidth={1} strokeDasharray="3 3" />
              <ReferenceArea x1={356} x2={360} y1={isoBounds.A_min} y2={isoBounds.A_max} fill="#1e40af" fillOpacity={0.1}>
                <Label value={`A:${results.A.toFixed(2)}"`} position="left" offset={8} style={{ fontSize: '11px', fontWeight: 'bold', fill: '#1e40af' }} />
              </ReferenceArea>

              <ReferenceLine segment={[{ x: 330, y: isoBounds.E_min }, { x: 345, y: isoBounds.E_min }]} stroke="#475569" strokeWidth={1} strokeDasharray="2 2" />
              <ReferenceLine segment={[{ x: 330, y: isoBounds.E_max }, { x: 345, y: isoBounds.E_max }]} stroke="#475569" strokeWidth={1} strokeDasharray="2 2" />
              <ReferenceArea x1={341} x2={345} y1={isoBounds.E_min} y2={isoBounds.E_max} fill="#475569" fillOpacity={0.1}>
                <Label value={`E:${results.E.toFixed(2)}"`} position="left" offset={8} style={{ fontSize: '10px', fontWeight: 'bold', fill: '#475569' }} />
              </ReferenceArea>

              {/* 核心数据曲线 */}
              <Line name="正向平均 x̄↑" dataKey="meanF" stroke={FORWARD_COLOR} strokeWidth={2.5} dot={{ r: 4, fill: FORWARD_COLOR, strokeWidth: 0 }} type="monotone" />
              <Line name="反向平均 x̄↓" dataKey="meanR" stroke={REVERSE_COLOR} strokeWidth={2.5} strokeDasharray="5 3" dot={{ r: 4, fill: REVERSE_COLOR, strokeWidth: 0 }} type="monotone" />

              {/* 置信区间 (2s) */}
              <Line name="置信上限 (2s)" dataKey="upperF" stroke={FORWARD_COLOR} strokeWidth={1} strokeDasharray="8 4" dot={false} type="monotone" strokeOpacity={0.4} />
              <Line dataKey="lowerF" stroke={FORWARD_COLOR} strokeWidth={1} strokeDasharray="8 4" dot={false} type="monotone" strokeOpacity={0.4} />

              {/* 双向平均线 */}
              <Line name="平均偏差 M" dataKey="meanBi" stroke={BI_COLOR} strokeWidth={3} dot={{ r: 2, fill: BI_COLOR }} type="monotone" />

              <Legend verticalAlign="bottom" align="center" height={40} iconType="plainline" wrapperStyle={{ fontSize: '11px', paddingTop: '20px' }} />
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        {/* 底部详细图例面板 */}
        <div className="mt-4 flex flex-wrap gap-x-8 gap-y-2 p-4 bg-slate-50 border border-slate-100 rounded-lg justify-center">
          <div className="flex items-center gap-2"><div className="w-4 h-0.5 bg-blue-800"></div><span className="text-[11px] text-slate-700 font-bold">A: 定位精度</span></div>
          <div className="flex items-center gap-2"><div className="w-4 h-0.5 bg-slate-500"></div><span className="text-[11px] text-slate-700 font-bold">E: 定位偏差</span></div>
          <div className="flex items-center gap-2"><div className="w-4 h-0.5 bg-slate-900"></div><span className="text-[11px] text-slate-700 font-bold">M: 平均偏差</span></div>
          <div className="flex items-center gap-2"><div className="w-2.5 h-2.5 rounded-full bg-red-700"></div><span className="text-[11px] text-slate-700 font-bold">B: 反向差值</span></div>
          <div className="flex items-center gap-2"><div className="w-2.5 h-2.5 rounded-full border-2 border-indigo-700"></div><span className="text-[11px] text-slate-700 font-bold">R: 重复精度</span></div>
        </div>
      </div>
    </div>
  );
};

